import React, { useState, useEffect, useRef, useCallback } from 'react';
import ControlPanel from './components/ControlPanel';
import VisualizerCanvas from './components/VisualizerCanvas';
import { VisualizerParams, DEFAULT_PARAMS } from './types';
import { useAudioAnalyzer } from './hooks/useAudioAnalyzer';

// Helper for interpolation
const lerp = (start: number, end: number, amt: number) => (1 - amt) * start + amt * end;

// Helper to get random number in range
const randomRange = (min: number, max: number) => Math.random() * (max - min) + min;

// Refined presets that are guaranteed to look good
const HARMONIC_PRESETS = [
  { k: 0.995, psi: 0.15, zoom: 150, z0_r: 0.05, z0_i: 0.05 }, // Classic Spiral
  { k: 1.002, psi: 0.5, zoom: 120, z0_r: 0, z0_i: 0 },         // Exploding Flower
  { k: 0.96, psi: 2.1, zoom: 180, z0_r: 0.3, z0_i: -0.3 },    // Tri-lobe chaos
  { k: 1.0, psi: 0.02, zoom: 90, z0_r: -0.8, z0_i: 0 },         // Horizontal Tunnel
  { k: 0.99, psi: 3.14, zoom: 200, z0_r: 0.1, z0_i: 0.1 },        // Binary flip
  { k: 1.03, psi: 0.8, zoom: 60, z0_r: 0.15, z0_i: 0.15 }       // Deep Zoom
];

const App: React.FC = () => {
  const [params, setParams] = useState<VisualizerParams>(DEFAULT_PARAMS);
  const { isActive, startAudio, stopAudio, getAudioMetrics } = useAudioAnalyzer();
  const [controlsVisible, setControlsVisible] = useState(true);

  // Refs for auto-pilot logic
  const hideTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const targetParamsRef = useRef<Partial<VisualizerParams>>({});
  const lastAutoUpdateRef = useRef<number>(0);
  const animationFrameRef = useRef<number>(0);

  const toggleAudio = () => {
    if (isActive) {
      stopAudio();
    } else {
      startAudio();
    }
  };

  // Activity handler to show controls and reset timer
  const handleUserActivity = useCallback(() => {
    setControlsVisible(true);

    if (hideTimeoutRef.current) {
      clearTimeout(hideTimeoutRef.current);
    }

    hideTimeoutRef.current = setTimeout(() => {
      setControlsVisible(false);
    }, 5000);
  }, []);

  // --- Auto Pilot Logic ---
  const generateHarmonicTarget = () => {
    const usePreset = Math.random() > 0.4; // 60% chance of random generation

    if (usePreset) {
      return { ...HARMONIC_PRESETS[Math.floor(Math.random() * HARMONIC_PRESETS.length)] };
    } else {
      // Smart Random Generation:
      // K must be VERY close to 1.0 to look good full screen.
      // 0.97 - 1.03 is the "Goldilocks Zone" for fluid patterns.
      const safeK = randomRange(0.97, 1.03); 

      // Zoom relates to K. If K > 1 (expanding), low zoom is better. If K < 1 (contracting), high zoom is better.
      const smartZoom = safeK > 1 ? randomRange(40, 100) : randomRange(120, 250);

      return {
        k: safeK,
        psi: randomRange(-3.14, 3.14), // Any rotation is fine
        zoom: smartZoom,
        // Keep translation small to keep pattern on screen
        z0_r: randomRange(-0.4, 0.4), 
        z0_i: randomRange(-0.4, 0.4)
      };
    }
  };

  useEffect(() => {
    if (!params.autoPilot) {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      return;
    }

    // Initialize target immediately if starting
    if (Object.keys(targetParamsRef.current).length === 0) {
      targetParamsRef.current = generateHarmonicTarget();
    }

    const updateLoop = () => {
      const now = Date.now();

      // 1. Determine Target (every 8-12 seconds for more breathing room)
      if (now - lastAutoUpdateRef.current > 10000) {

        targetParamsRef.current = generateHarmonicTarget();

        // Occasionally shift color base for variety
        if (Math.random() > 0.6) {
           targetParamsRef.current.baseHue = Math.floor(Math.random() * 360);
        }

        lastAutoUpdateRef.current = now;
      }

      // 2. Interpolate towards target
      // We use a very low lerp factor for "Fluidity". 
      // It makes changes imperceptible but constant.
      const lerpFactor = 0.003; 

      setParams(current => {
        const target = targetParamsRef.current;

        // Helper to check and lerp if exists
        const move = (curr: number, tgt: number | undefined) => 
          tgt !== undefined ? lerp(curr, tgt, lerpFactor) : curr;

        return {
          ...current,
          k: move(current.k, target.k),
          psi: move(current.psi, target.psi),
          zoom: move(current.zoom, target.zoom),
          z0_r: move(current.z0_r, target.z0_r),
          z0_i: move(current.z0_i, target.z0_i),
          // Slowly drift color if target exists
          baseHue: target.baseHue ? lerp(current.baseHue, target.baseHue, 0.001) : current.baseHue
        };
      });

      animationFrameRef.current = requestAnimationFrame(updateLoop);
    };

    updateLoop();

    return () => {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [params.autoPilot]);

  useEffect(() => {
    // Attach event listeners for activity
    window.addEventListener('mousemove', handleUserActivity);
    window.addEventListener('touchstart', handleUserActivity);
    window.addEventListener('click', handleUserActivity);
    window.addEventListener('keydown', handleUserActivity);

    // Initial timer
    handleUserActivity();

    return () => {
      window.removeEventListener('mousemove', handleUserActivity);
      window.removeEventListener('touchstart', handleUserActivity);
      window.removeEventListener('click', handleUserActivity);
      window.removeEventListener('keydown', handleUserActivity);
      if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [handleUserActivity]);

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-black text-white relative">

      {/* Main Canvas Area - Always Fullscreen */}
      <div className="absolute inset-0 z-0">
        <VisualizerCanvas 
          params={params} 
          getAudioMetrics={getAudioMetrics}
        />
      </div>

      {/* Status Indicators Overlay - Always visible but subtle */}
      <div className="absolute top-6 right-6 flex gap-4 pointer-events-none z-20 transition-opacity duration-500" style={{ opacity: controlsVisible ? 1 : 0.5 }}>
           <div className={`flex items-center gap-2 px-3 py-1 rounded-full border text-xs font-mono backdrop-blur-sm transition-colors duration-300
             ${isActive 
               ? 'bg-red-500/10 border-red-500/40 text-red-400 animate-pulse' 
               : 'bg-gray-800/30 border-gray-700 text-gray-500'}
           `}>
             <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-red-500' : 'bg-gray-500'}`}></div>
             {isActive ? 'MIC LIVE' : 'MIC OFF'}
           </div>

           {params.autoPilot && (
             <div className="flex items-center gap-2 px-3 py-1 rounded-full border border-indigo-500/40 bg-indigo-500/10 text-indigo-400 text-xs font-mono backdrop-blur-sm animate-pulse">
                AUTO-PILOT ACTIVE
             </div>
           )}
      </div>

      {/* Floating Sidebar Controls */}
      <div 
        className={`
          absolute top-0 left-0 h-full z-30
          transform transition-transform duration-500 ease-in-out
          ${controlsVisible ? 'translate-x-0' : '-translate-x-full'}
        `}
        // Prevent hiding when interacting with the panel itself
        onMouseEnter={() => {
           if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
           setControlsVisible(true);
        }}
        onMouseLeave={handleUserActivity}
      >
        <ControlPanel 
          params={params} 
          setParams={setParams} 
          audioActive={isActive}
          toggleAudio={toggleAudio}
        />
      </div>
    </div>
  );
};

export default App;

import { useEffect, useRef, useState } from 'react';

export const useAudioAnalyzer = () => {
  const [isActive, setIsActive] = useState(false);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const dataArrayRef = useRef<Uint8Array | null>(null);

  const startAudio = async () => {
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }

      // Resume context if suspended (browser policy)
      if (audioContextRef.current.state === 'suspended') {
        await audioContextRef.current.resume();
      }

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      analyserRef.current = audioContextRef.current.createAnalyser();
      analyserRef.current.fftSize = 4096; // Higher resolution for better bass detection
      analyserRef.current.smoothingTimeConstant = 0.88; // Smoother transition between frames

      sourceRef.current = audioContextRef.current.createMediaStreamSource(stream);
      sourceRef.current.connect(analyserRef.current);

      dataArrayRef.current = new Uint8Array(analyserRef.current.frequencyBinCount);

      setIsActive(true);
    } catch (err) {
      console.error("Error accessing microphone:", err);
      setIsActive(false);
    }
  };

  const stopAudio = () => {
    if (sourceRef.current) {
      sourceRef.current.disconnect();
    }
    setIsActive(false);
  };

  const getAudioMetrics = (sensitivity: number, freqRange: number): { volume: number, frequency: number } => {
    if (!analyserRef.current || !dataArrayRef.current || !isActive) {
      return { volume: 0, frequency: 0 };
    }

    analyserRef.current.getByteFrequencyData(dataArrayRef.current);

    // Limit range to relevant frequencies
    const rangeLimit = Math.floor(dataArrayRef.current.length * freqRange);

    let totalMagnitude = 0;
    let weightedFrequencySum = 0;
    let maxMagnitude = 0;

    // Calculate Spectral Centroid (Center of Mass of the spectrum)
    // This gives a much smoother "perceived pitch" than just finding the max bin
    for (let i = 0; i < rangeLimit; i++) {
      const val = dataArrayRef.current[i];

      // Filter out low-level noise to avoid color jitter in silence
      if (val > 30) { 
        totalMagnitude += val;
        weightedFrequencySum += i * val;
        if (val > maxMagnitude) maxMagnitude = val;
      }
    }

    // Normalized volume (0-1)
    // Using RMS-like approximation from average magnitude
    const average = rangeLimit > 0 ? totalMagnitude / rangeLimit : 0;
    const volume = Math.min((average / 60) * sensitivity, 1.0); 

    // Normalized frequency (0-1) based on Centroid
    // If totalMagnitude is low, keep previous frequency or default to 0 to avoid division by zero
    let frequency = 0;
    if (totalMagnitude > 0) {
      const centroidBin = weightedFrequencySum / totalMagnitude;
      frequency = centroidBin / rangeLimit;
    }

    return { volume, frequency };
  };

  return {
    isActive,
    startAudio,
    stopAudio,
    getAudioMetrics
  };
};

import React, { useRef, useEffect } from 'react';
import { VisualizerParams } from '../types';

interface VisualizerCanvasProps {
  params: VisualizerParams;
  getAudioMetrics: (sensitivity: number, freqRange: number) => { volume: number, frequency: number };
}

// Shortest path interpolation for angles (prevents spinning 360 degrees to go from 350 to 10)
const lerpAngle = (start: number, end: number, amt: number) => {
  const d = end - start;
  // Calculate shortest distance around the circle
  const delta = (d + 540) % 360 - 180; 
  return (start + delta * amt + 360) % 360;
};

const VisualizerCanvas: React.FC<VisualizerCanvasProps> = ({ params, getAudioMetrics }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const requestRef = useRef<number>();
  const timeRef = useRef<number>(0);
  const currentHueRef = useRef<number>(params.baseHue);

  const draw = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d', { alpha: false }); // Optimize for no alpha channel on background
    if (!ctx) return;

    // Get Audio Data
    const { volume, frequency } = getAudioMetrics(params.sensitivity, params.freqRange);

    // Dynamic parameter adjustments based on audio
    // Volume expands the spiral (modifies K)
    // Frequency rotates the spiral (modifies Psi)
    const dynamicK = params.k + (volume * 0.02 * (params.k > 1 ? 1 : -1)); // Expand or contract based on base state

    // Smooth frequency influence
    const dynamicPsi = params.psi + (frequency * 0.1); 

    // Visual setup
    const width = canvas.width;
    const height = canvas.height;
    const cx = width / 2;
    const cy = height / 2;

    // Trail effect (semi-transparent clear)
    ctx.fillStyle = `rgba(5, 5, 5, ${params.trail})`;
    ctx.fillRect(0, 0, width, height);

    // Prepare Math
    // Euler's rotation: e^(i*psi)
    const rotReal = Math.cos(dynamicPsi);
    const rotImag = Math.sin(dynamicPsi);

    let zReal = 1 + (volume * 0.5); // Initial displacement reacts to beat
    let zImag = 1 + (volume * 0.5);

    // Start drawing
    ctx.beginPath();

    // Starting point
    let prevX = cx + zReal * params.zoom;
    let prevY = cy - zImag * params.zoom;

    ctx.moveTo(prevX, prevY);

    // Color Logic Preparation
    let displayBaseHue;

    if (params.harmonicColor) {
      // HARMONIC COLOR LOGIC
      // 1. Logarithmic mapping: Human ear hears pitch logarithmically.
      // We expand the lower frequency range (Bass/Mids) to occupy more color space.
      // "frequency" comes in 0-1 linear.
      const logFreq = Math.log2(1 + frequency * 32) / 5; // Normalized roughly 0-1 but curved

      // 2. Sensitivity controls the spread across the color wheel
      const sensitivityMultiplier = params.harmonicSensitivity || 1.0;

      // 3. Map to hue
      // We start at baseHue and rotate based on pitch
      const hueOffset = logFreq * 360 * sensitivityMultiplier;

      const targetHue = (params.baseHue + hueOffset) % 360;

      // 4. Smooth Transition
      // If volume is high (beat), transition color faster. If low, drift slowly.
      const colorLerpSpeed = volume > 0.1 ? 0.15 : 0.05;

      currentHueRef.current = lerpAngle(currentHueRef.current, targetHue, colorLerpSpeed);
      displayBaseHue = currentHueRef.current;
    } else {
      // Standard time-based cycling
      timeRef.current += params.hueSpeed;
      currentHueRef.current = (params.baseHue + timeRef.current) % 360;
      displayBaseHue = currentHueRef.current;
    }

    for (let n = 0; n < params.iter; n++) {
        // Complex Recurrence: Zn+1 = Zn * (k * rot) + Z0

        // 1. Scale
        const zrK = zReal * dynamicK;
        const ziK = zImag * dynamicK;

        // 2. Rotate (Complex Multiplication)
        let nextReal = (zrK * rotReal - ziK * rotImag);
        let nextImag = (zrK * rotImag + ziK * rotReal);

        // 3. Translate
        nextReal += params.z0_r;
        nextImag += params.z0_i;

        // Update Z
        zReal = nextReal;
        zImag = nextImag;

        // Project to Screen
        const px = cx + zReal * params.zoom;
        const py = cy - zImag * params.zoom;

        ctx.lineTo(px, py);

        // Optional: Draw vertices for more definition on high volume
        if (volume > 0.6 && n % 5 === 0) {
            ctx.fillStyle = `rgba(255, 255, 255, ${volume * 0.5})`;
            ctx.fillRect(px - 1, py - 1, 2, 2);
        }

        prevX = px;
        prevY = py;
    }

    // Gradient Application
    const gradient = ctx.createLinearGradient(0, 0, width, height);

    // Dynamic gradient based on audio intensity
    const intensity = Math.min(volume * 80, 50); // Cap intensity boost

    // Calculate secondary hue based on range
    const secondaryHue = (displayBaseHue + params.hueRange) % 360;

    const color1 = `hsl(${displayBaseHue}, ${params.saturation}%, ${Math.min(100, params.brightness + intensity)}%)`;
    const color2 = `hsl(${secondaryHue}, ${params.saturation}%, ${Math.max(0, params.brightness - 20 + intensity)}%)`;

    gradient.addColorStop(0, color1);
    gradient.addColorStop(1, color2);

    ctx.strokeStyle = gradient;

    // Line width reacts to bass/volume
    ctx.lineWidth = 1 + (volume * 3);
    ctx.lineJoin = 'round';
    ctx.lineCap = 'round';

    // Add glow effect using the base color
    ctx.shadowBlur = volume * 20;
    ctx.shadowColor = `hsl(${displayBaseHue}, ${params.saturation}%, 60%)`;

    ctx.stroke();

    // Reset shadow for performance
    ctx.shadowBlur = 0;

    requestRef.current = requestAnimationFrame(draw);
  };

  useEffect(() => {
    // Handle resize
    const resizeObserver = new ResizeObserver(entries => {
      if (!canvasRef.current) return;
      const { width, height } = entries[0].contentRect;
      // Handle DPI
      const dpr = window.devicePixelRatio || 1;
      canvasRef.current.width = width * dpr;
      canvasRef.current.height = height * dpr;

      // Scale context to match DPI
      const ctx = canvasRef.current.getContext('2d');
      if(ctx) ctx.scale(dpr, dpr);

      // We actually want the internal resolution to match screen pixels for crisp lines, 
      // but simpler: just set width/height attributes to clientWidth/Height for 1:1 mapping
      canvasRef.current.width = width;
      canvasRef.current.height = height;
    });

    if (canvasRef.current?.parentElement) {
      resizeObserver.observe(canvasRef.current.parentElement);
    }

    requestRef.current = requestAnimationFrame(draw);

    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
      resizeObserver.disconnect();
    };
  }, [params, getAudioMetrics]); // Re-bind effect when static params change

  return (
    <div className="w-full h-full relative bg-black overflow-hidden shadow-inner">
      <canvas 
        ref={canvasRef} 
        className="block w-full h-full"
      />
      {/* Overlay info */}
      <div className="absolute bottom-6 right-6 font-mono text-xs text-gray-500 pointer-events-none select-none">
        <div className="flex flex-col items-end gap-1">
          <span>RENDER: WEBGL2_COMPAT</span>
          <span>MATH: RECURSIVE_COMPLEX_Z</span>
          {params.harmonicColor && <span className="text-pink-500">MODE: HARMONIC_SYNC</span>}
        </div>
      </div>
    </div>
  );
};

