import React, { useState, useEffect, useRef, useCallback } from 'react';
import ControlPanel from './components/ControlPanel';
import VisualizerCanvas from './components/VisualizerCanvas';
import { VisualizerParams, DEFAULT_PARAMS } from './types';
import { useAudioAnalyzer } from './hooks/useAudioAnalyzer';

// Helper for interpolation
const lerp = (start: number, end: number, amt: number) => (1 - amt) * start + amt * end;

const App: React.FC = () => {
  const [params, setParams] = useState<VisualizerParams>(DEFAULT_PARAMS);
  const { isActive, startAudio, stopAudio, getAudioMetrics } = useAudioAnalyzer();
  const [controlsVisible, setControlsVisible] = useState(true);

  // Refs for auto-pilot logic
  const hideTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const animationFrameRef = useRef<number>(0);

  // Internal state for the auto-pilot's "Virtual Target"
  // We don't store this in React state to avoid re-renders, we just drift the params towards this
  const driftRef = useRef({
    time: 0,
    targetK: 1.0,
    targetPsi: 0.15,
    targetZ0_r: 0.05,
    targetZ0_i: 0.05,
    targetZoom: 150
  });

  const toggleAudio = () => {
    if (isActive) {
      stopAudio();
    } else {
      startAudio();
    }
  };

  const handleUserActivity = useCallback(() => {
    setControlsVisible(true);

    if (hideTimeoutRef.current) {
      clearTimeout(hideTimeoutRef.current);
    }

    hideTimeoutRef.current = setTimeout(() => {
      setControlsVisible(false);
    }, 5000);
  }, []);

  // --- Fluid Auto Pilot Logic ---
  useEffect(() => {
    if (!params.autoPilot) {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      return;
    }

    const updateLoop = () => {
      // 1. Get Real-time Audio Data to drive the "Brain"
      const { volume, frequency } = getAudioMetrics(params.sensitivity, params.freqRange);

      const d = driftRef.current;

      // Advance internal time based on user speed setting and audio intensity
      // If music is fast/loud, we drift faster.
      const timeStep = 0.005 * params.autoSpeed * (1 + volume * 2); 
      d.time += timeStep;

      // 2. Calculate "Targets" based on Audio & Math
      // We want Z0 to wander through "interesting" parts of the complex plane (Julia sets)
      // Lissajous-like curves ensure we stay in a nice area
      const wanderRadius = 0.6 + (volume * 0.2); // Expand search area on beat

      // Frequency dictates the "Angle" of the shape in the complex plane
      // Volume dictates the "Extension"
      const freqFactor = frequency * Math.PI * 4;

      // Target Z0 drifts in a fluid, circular/lissajous pattern modified by the note (frequency)
      d.targetZ0_r = Math.cos(d.time + freqFactor) * wanderRadius * 0.8;
      d.targetZ0_i = Math.sin(d.time * 0.7 + freqFactor) * wanderRadius * 0.8;

      // Target K (Expansion):
      // Keep it extremely close to 1.0 for full-screen Kaleidoscope effects.
      // Beat (volume) pushes it slightly outward (>1) or inward (<1) rhythmically.
      // We oscillate K slowly over time, modulated by immediate volume.
      const breathing = Math.sin(d.time * 2) * 0.02; 
      d.targetK = 1.0 + breathing + (volume * 0.01 * (Math.random() > 0.5 ? 1 : -1));

      // Target Psi (Rotation):
      // Rotates continuously based on speed, kicks on beat.
      d.targetPsi = (d.targetPsi + (params.autoSpeed * 0.01) + (volume * 0.05)) % (Math.PI * 2);

      // Target Zoom:
      // Zoom out on drops (high vol), Zoom in on quiet parts, or vice versa.
      // Let's make it breathe.
      d.targetZoom = 100 + (Math.sin(d.time * 0.5) * 50) + (volume * 20);

      // 3. Apply VISCOSITY (Fluid interpolation)
      // Viscosity 1.0 = frozen (lerp 0). Viscosity 0.0 = Instant (lerp 1).
      // We map 0.0-1.0 viscosity to a useful lerp range (e.g., 0.2 to 0.001)
      const rawViscosity = params.autoViscosity ?? 0.8;

      // Inverse logarithmic-ish mapping for natural feeling
      // High viscosity -> tiny lerp factor.
      const lerpFactor = 0.001 + (1 - rawViscosity) * 0.05;

      // Volume kick: When a beat hits (high volume), we momentarily lower viscosity
      // to allow the visual to "snap" to the beat, then float.
      const dynamicLerp = lerpFactor * (1 + volume * 2);

      setParams(current => ({
        ...current,
        // Interpolate current towards target using viscosity
        k: lerp(current.k, d.targetK, dynamicLerp),
        psi: lerp(current.psi, d.targetPsi, dynamicLerp), // Rotation
        z0_r: lerp(current.z0_r, d.targetZ0_r, dynamicLerp),
        z0_i: lerp(current.z0_i, d.targetZ0_i, dynamicLerp),
        zoom: lerp(current.zoom, d.targetZoom, dynamicLerp),

        // Auto-Harmonize Color if not manually overridden
        // Drifts base hue slowly over time
        baseHue: params.harmonicColor ? current.baseHue : (current.baseHue + params.autoSpeed * 0.2) % 360
      }));

      animationFrameRef.current = requestAnimationFrame(updateLoop);
    };

    updateLoop();

    return () => {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [params.autoPilot, params.autoSpeed, params.autoViscosity, isActive]); // Dependencies updated

  useEffect(() => {
    // Attach event listeners for activity
    window.addEventListener('mousemove', handleUserActivity);
    window.addEventListener('touchstart', handleUserActivity);
    window.addEventListener('click', handleUserActivity);
    window.addEventListener('keydown', handleUserActivity);

    // Initial timer
    handleUserActivity();

    return () => {
      window.removeEventListener('mousemove', handleUserActivity);
      window.removeEventListener('touchstart', handleUserActivity);
      window.removeEventListener('click', handleUserActivity);
      window.removeEventListener('keydown', handleUserActivity);
      if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [handleUserActivity]);

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-black text-white relative">

      {/* Main Canvas Area - Always Fullscreen */}
      <div className="absolute inset-0 z-0">
        <VisualizerCanvas 
          params={params} 
          getAudioMetrics={getAudioMetrics}
        />
      </div>

      {/* Status Indicators Overlay - Always visible but subtle */}
      <div className="absolute top-6 right-6 flex gap-4 pointer-events-none z-20 transition-opacity duration-500" style={{ opacity: controlsVisible ? 1 : 0.5 }}>
           <div className={`flex items-center gap-2 px-3 py-1 rounded-full border text-xs font-mono backdrop-blur-sm transition-colors duration-300
             ${isActive 
               ? 'bg-red-500/10 border-red-500/40 text-red-400 animate-pulse' 
               : 'bg-gray-800/30 border-gray-700 text-gray-500'}
           `}>
             <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-red-500' : 'bg-gray-500'}`}></div>
             {isActive ? 'MIC LIVE' : 'MIC OFF'}
           </div>

           {params.autoPilot && (
             <div className="flex items-center gap-2 px-3 py-1 rounded-full border border-indigo-500/40 bg-indigo-500/10 text-indigo-400 text-xs font-mono backdrop-blur-sm animate-pulse">
                FLUID PILOT
             </div>
           )}
      </div>

      {/* Floating Sidebar Controls */}
      <div 
        className={`
          absolute top-0 left-0 h-full z-30
          transform transition-transform duration-500 ease-in-out
          ${controlsVisible ? 'translate-x-0' : '-translate-x-full'}
        `}
        // Prevent hiding when interacting with the panel itself
        onMouseEnter={() => {
           if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
           setControlsVisible(true);
        }}
        onMouseLeave={handleUserActivity}
      >
        <ControlPanel 
          params={params} 
          setParams={setParams} 
          audioActive={isActive}
          toggleAudio={toggleAudio}
        />
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import ControlPanel from './components/ControlPanel';
import VisualizerCanvas from './components/VisualizerCanvas';
import { VisualizerParams, DEFAULT_PARAMS } from './types';
import { useAudioAnalyzer } from './hooks/useAudioAnalyzer';

// --- FRACTAL ATTRACTORS ---
// These are mathematically proven "Sweet Spots" in the Julia Set that create distinct, beautiful patterns.
// The AutoPilot will interpolate smoothly between these states instead of random wandering.
const ATTRACTORS = [
  // 1. Classic Spiral / Sea Horse Tail
  { k: 0.99, psi: 0.1, z0_r: 0.28, z0_i: 0.01, zoom: 180 },
  // 2. The Dendrite (Lightning-like branching)
  { k: 1.0, psi: 1.5, z0_r: 0.0, z0_i: 1.0, zoom: 120 },
  // 3. Siegel Disk (Golden Ratio rotation - very fluid)
  { k: 1.0, psi: 2.399, z0_r: -0.3905, z0_i: -0.5867, zoom: 140 },
  // 4. Douady's Rabbit (Triangular symmetry)
  { k: 0.98, psi: 0.5, z0_r: -0.122, z0_i: 0.744, zoom: 160 },
  // 5. Kaleidoscope Core (High symmetry)
  { k: 1.005, psi: 3.14159/3, z0_r: -0.75, z0_i: 0.0, zoom: 80 },
  // 6. Bio-Organic (Cellular look)
  { k: 0.97, psi: 0.8, z0_r: 0.285, z0_i: 0.01, zoom: 200 },
  // 7. The Void (Tunneling effect)
  { k: 1.02, psi: 0.05, z0_r: -0.8, z0_i: 0.156, zoom: 60 }
];

// Helper for Cosine Interpolation (Smoother than linear)
const smoothStep = (t: number) => (1 - Math.cos(t * Math.PI)) / 2;
const lerp = (start: number, end: number, amt: number) => (1 - amt) * start + amt * end;

const App: React.FC = () => {
  const [params, setParams] = useState<VisualizerParams>(DEFAULT_PARAMS);
  const { isActive, startAudio, stopAudio, getAudioMetrics } = useAudioAnalyzer();
  const [controlsVisible, setControlsVisible] = useState(true);

  // Logic Refs
  const hideTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const animationFrameRef = useRef<number>(0);

  // --- CHOREOGRAPHER STATE ---
  // Keeps track of where we are in the "Fractal Journey"
  const journeyRef = useRef({
    currentIndex: 0,
    nextIndex: 1,
    progress: 0, // 0.0 to 1.0 transition progress
    lastSwitchTime: 0,
    // Current "Physical" values (smoothed)
    current: { ...DEFAULT_PARAMS } 
  });

  const toggleAudio = () => {
    if (isActive) {
      stopAudio();
    } else {
      startAudio();
    }
  };

  const handleUserActivity = useCallback(() => {
    setControlsVisible(true);
    if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
    hideTimeoutRef.current = setTimeout(() => {
      setControlsVisible(false);
    }, 5000);
  }, []);

  // --- ENGINE: The Fluid Choreographer ---
  useEffect(() => {
    if (!params.autoPilot) {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      return;
    }

    const updateLoop = () => {
      const { volume, frequency } = getAudioMetrics(params.sensitivity, params.freqRange);
      const j = journeyRef.current;

      // 1. Advance The Journey (Transition between Attractors)
      // Speed depends on user setting + slight boost from high energy music
      const speedBase = params.autoSpeed * 0.002; 
      const speedBoost = volume * 0.002; 
      j.progress += speedBase + speedBoost;

      // When transition is complete, pick a new destination
      if (j.progress >= 1.0) {
        j.progress = 0;
        j.currentIndex = j.nextIndex;
        // Pick random next attractor, ensure it's different
        let next = Math.floor(Math.random() * ATTRACTORS.length);
        while (next === j.currentIndex) next = Math.floor(Math.random() * ATTRACTORS.length);
        j.nextIndex = next;
      }

      // 2. Interpolate Base Geometry (The "Kaleidoscope" Structure)
      const startState = ATTRACTORS[j.currentIndex];
      const endState = ATTRACTORS[j.nextIndex];
      const t = smoothStep(j.progress); // Smooth ease-in-ease-out curve

      // Calculate the "Ideal" geometry for this moment in time
      const idealK = lerp(startState.k, endState.k, t);
      const idealPsi = lerp(startState.psi, endState.psi, t);
      const idealZ0_r = lerp(startState.z0_r, endState.z0_r, t);
      const idealZ0_i = lerp(startState.z0_i, endState.z0_i, t);
      const idealZoom = lerp(startState.zoom, endState.zoom, t);

      // 3. Apply Audio Modulation (The "Life")
      // We don't just replace values, we add *energy* to them.

      // BREATHING: Volume modifies Expansion (K). 
      // High volume pushes K away from 1.0 (creates movement), Silence brings it to 1.0 (Stillness)
      const kPulse = (volume * 0.015) * Math.sin(Date.now() / 1000); 

      // DANCING: Frequency modifies Rotation (Psi).
      // High notes rotate the kaleidoscope faster.
      const psiSpin = frequency * 0.1;

      // MORPHING: Volume modifies Shape (Z0).
      // Bass morphs the fractal boundaries.
      const z0Pulse = volume * 0.05;

      // 4. Apply Viscosity (The "Fluid" Physics)
      // We assume the internal params are the "Physical Object" and we pull them towards Ideal + Audio
      // Higher viscosity = slower reaction = smoother liquid look.

      // Map 0-1 viscosity slider to a useful interpolation factor (0.1 to 0.005)
      const viscosityFactor = 0.005 + (1 - params.autoViscosity) * 0.08;

      // Update internal smoothed state
      j.current.k = lerp(j.current.k, idealK + kPulse, viscosityFactor);
      j.current.psi = lerp(j.current.psi, idealPsi + psiSpin, viscosityFactor);
      j.current.z0_r = lerp(j.current.z0_r, idealZ0_r + z0Pulse, viscosityFactor);
      j.current.z0_i = lerp(j.current.z0_i, idealZ0_i - z0Pulse, viscosityFactor); // Asymmetric morph
      j.current.zoom = lerp(j.current.zoom, idealZoom - (volume * 20), viscosityFactor); // Zoom out on loud beats

      // 5. Update React State
      setParams(prev => ({
        ...prev,
        k: j.current.k,
        psi: j.current.psi,
        z0_r: j.current.z0_r,
        z0_i: j.current.z0_i,
        zoom: j.current.zoom,
        // Slowly drift base color if harmonic mode is OFF, otherwise let Harmonic Logic handle it
        baseHue: params.harmonicColor ? prev.baseHue : (prev.baseHue + 0.1) % 360
      }));

      animationFrameRef.current = requestAnimationFrame(updateLoop);
    };

    // Initialize the internal state with current params to avoid jump
    journeyRef.current.current = { ...params };
    updateLoop();

    return () => {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [params.autoPilot, params.autoSpeed, params.autoViscosity, isActive]); 

  // Standard Event Listeners
  useEffect(() => {
    window.addEventListener('mousemove', handleUserActivity);
    window.addEventListener('touchstart', handleUserActivity);
    window.addEventListener('click', handleUserActivity);
    window.addEventListener('keydown', handleUserActivity);
    handleUserActivity();
    return () => {
      window.removeEventListener('mousemove', handleUserActivity);
      window.removeEventListener('touchstart', handleUserActivity);
      window.removeEventListener('click', handleUserActivity);
      window.removeEventListener('keydown', handleUserActivity);
      if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [handleUserActivity]);

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-black text-white relative">
      <div className="absolute inset-0 z-0">
        <VisualizerCanvas 
          params={params} 
          getAudioMetrics={getAudioMetrics}
        />
      </div>

      <div className="absolute top-6 right-6 flex gap-4 pointer-events-none z-20 transition-opacity duration-500" style={{ opacity: controlsVisible ? 1 : 0.5 }}>
           <div className={`flex items-center gap-2 px-3 py-1 rounded-full border text-xs font-mono backdrop-blur-sm transition-colors duration-300
             ${isActive 
               ? 'bg-red-500/10 border-red-500/40 text-red-400 animate-pulse' 
               : 'bg-gray-800/30 border-gray-700 text-gray-500'}
           `}>
             <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-red-500' : 'bg-gray-500'}`}></div>
             {isActive ? 'MIC LIVE' : 'MIC OFF'}
           </div>

           {params.autoPilot && (
             <div className="flex items-center gap-2 px-3 py-1 rounded-full border border-indigo-500/40 bg-indigo-500/10 text-indigo-400 text-xs font-mono backdrop-blur-sm shadow-[0_0_15px_rgba(99,102,241,0.3)]">
                <span className="animate-spin mr-1">❖</span> FLUID ENGINE
             </div>
           )}
      </div>

      <div 
        className={`
          absolute top-0 left-0 h-full z-30
          transform transition-transform duration-500 ease-in-out
          ${controlsVisible ? 'translate-x-0' : '-translate-x-full'}
        `}
        onMouseEnter={() => {
           if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
           setControlsVisible(true);
        }}
        onMouseLeave={handleUserActivity}
      >
        <ControlPanel 
          params={params} 
          setParams={setParams} 
          audioActive={isActive}
          toggleAudio={toggleAudio}
        />
      </div>
    </div>
  );
};

export default App;

