import React, { useState, useEffect, useRef, useCallback } from 'react';
import ControlPanel from './components/ControlPanel';
import VisualizerCanvas from './components/VisualizerCanvas';
import { VisualizerParams, DEFAULT_PARAMS } from './types';
import { useAudioAnalyzer } from './hooks/useAudioAnalyzer';

// --- HARMONIC GEOMETRY DEFINITIONS ---
// Instead of random points, we define "Sacred Geometry" angles.
// These angles guarantee a coherent, symmetric, kaleidoscopic look.
const HARMONIC_ANGLES = [
  2.39996,          // Golden Angle (Phyllotaxis / Nature)
  Math.PI / 2,      // 90° (Square Symmetry)
  Math.PI / 3,      // 60° (Hexagonal Symmetry)
  Math.PI / 4,      // 45° (Octagonal Symmetry)
  (2 * Math.PI) / 5,// 72° (Pentagonal Symmetry)
  (2 * Math.PI) / 3,// 120° (Triangular)
  0.15,             // The Classic Logarithmic Spiral
  3.14159           // 180° (Linear Oscillation)
];

// Linear interpolation helper
const lerp = (start: number, end: number, amt: number) => (1 - amt) * start + amt * end;

// Circular interpolation for angles to avoid spinning the wrong way
const lerpAngle = (start: number, end: number, amt: number) => {
  const d = end - start;
  const delta = (d + Math.PI * 2 + Math.PI) % (Math.PI * 2) - Math.PI;
  return start + delta * amt;
};

const App: React.FC = () => {
  const [params, setParams] = useState<VisualizerParams>(DEFAULT_PARAMS);
  const { isActive, startAudio, stopAudio, getAudioMetrics } = useAudioAnalyzer();
  const [controlsVisible, setControlsVisible] = useState(true);

  // Logic Refs
  const hideTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const animationFrameRef = useRef<number>(0);

  // --- INTELLIGENT PILOT STATE ---
  const pilotRef = useRef({
    targetK: 1.0,
    targetPsi: 2.399,
    targetZ0_r: 0.0,
    targetZ0_i: 0.0,
    targetZoom: 0.35,
    lastBeatTime: 0,
    currentParams: { ...DEFAULT_PARAMS }
  });

  const toggleAudio = () => {
    if (isActive) {
      stopAudio();
    } else {
      startAudio();
    }
  };

  const handleUserActivity = useCallback(() => {
    setControlsVisible(true);
    if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
    hideTimeoutRef.current = setTimeout(() => {
      setControlsVisible(false);
    }, 5000);
  }, []);

  // --- ENGINE: HARMONIC RESONANCE PILOT ---
  useEffect(() => {
    if (!params.autoPilot) {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      return;
    }

    const updateLoop = () => {
      // 1. ANALYZE AUDIO
      const { volume, frequency } = getAudioMetrics(params.sensitivity, params.freqRange);
      const now = Date.now();
      const p = pilotRef.current;

      // 2. INTELLIGENT TARGETING
      // We only change the fundamental geometry (Angle/Psi) when there is significant change
      // or continuously drift it very slowly.

      // Determine the "Harmonic Slot" based on frequency.
      // We map the 0-1 frequency range to our list of sacred angles.
      // This creates a "Kaleidoscope that dances to the pitch".
      const angleIndex = Math.floor(frequency * HARMONIC_ANGLES.length * 0.99); // 0.99 to avoid overflow
      const harmonicPsi = HARMONIC_ANGLES[Math.min(angleIndex, HARMONIC_ANGLES.length - 1)];

      // TARGET: ANGLE (PSI)
      // We pull the target towards this harmonic angle.
      // We add a tiny bit of "drift" (time-based) so it's not static.
      const drift = Math.sin(now * 0.0001 * params.autoSpeed) * 0.1;
      p.targetPsi = harmonicPsi + drift;

      // TARGET: EXPANSION (K)
      // To keep it full screen and centered, K must be approx 1.0.
      // Volume > creates expansion. Quiet > creates contraction.
      // Range: 0.98 to 1.02. Very tight control is needed for stability.
      const expansionEnergy = volume * 0.04;
      // Oscillate K slightly to create "Breathing"
      const breathe = Math.sin(now * 0.001) * 0.005;
      p.targetK = 1.0 + breathe + expansionEnergy;

      // TARGET: CENTER (Z0)
      // To keep it centered, Z0 must be (0,0).
      // However, to give it 3D depth, we allow it to orbit microscopically around 0.
      // Radius of orbit proportional to volume (More loud = more wobble).
      const wobbleRadius = volume * 0.05;
      p.targetZ0_r = Math.cos(now * 0.0005) * wobbleRadius;
      p.targetZ0_i = Math.sin(now * 0.0005) * wobbleRadius;

      // TARGET: ZOOM
      // Zoom out on drops (loud), zoom in on quiet.
      // Base zoom 0.35.
      p.targetZoom = 0.35 - (volume * 0.1);


      // 3. FLUID PHYSICS (VISCOSITY)
      // This is the key to "Smoothness". We never set params directly.
      // We interpolate current -> target.

      const viscosity = params.autoViscosity ?? 0.95;
      // Calculate interpolation factor (alpha). Higher viscosity = Lower alpha.
      // Using exponential mapping for natural feel.
      let alpha = (1 - viscosity) * 0.1;

      // Dynamic Viscosity: When volume is high (beat), we allow faster movement (lower viscosity)
      // This makes the visual "hit" with the drum, then "float" in the silence.
      if (volume > 0.3) {
        alpha *= 1.5;
      }

      // Limit alpha to avoid instability
      alpha = Math.min(alpha, 0.2);
      alpha = Math.max(alpha, 0.001);

      // Interpolate
      p.currentParams.k = lerp(p.currentParams.k, p.targetK, alpha);
      p.currentParams.psi = lerpAngle(p.currentParams.psi, p.targetPsi, alpha);
      p.currentParams.z0_r = lerp(p.currentParams.z0_r, p.targetZ0_r, alpha);
      p.currentParams.z0_i = lerp(p.currentParams.z0_i, p.targetZ0_i, alpha);
      p.currentParams.zoom = lerp(p.currentParams.zoom, p.targetZoom, alpha);

      // 4. APPLY TO STATE
      setParams(prev => ({
        ...prev,
        k: p.currentParams.k,
        psi: p.currentParams.psi,
        z0_r: p.currentParams.z0_r,
        z0_i: p.currentParams.z0_i,
        zoom: p.currentParams.zoom,
        // Slowly rotate color if not in harmonic color mode
        baseHue: params.harmonicColor ? prev.baseHue : (prev.baseHue + 0.1) % 360
      }));

      animationFrameRef.current = requestAnimationFrame(updateLoop);
    };

    // Initialize Pilot State with current params to prevent jumps
    pilotRef.current.currentParams = { ...params };
    updateLoop();

    return () => {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [params.autoPilot, params.autoSpeed, params.autoViscosity, isActive]); 

  // Standard Event Listeners
  useEffect(() => {
    window.addEventListener('mousemove', handleUserActivity);
    window.addEventListener('touchstart', handleUserActivity);
    window.addEventListener('click', handleUserActivity);
    window.addEventListener('keydown', handleUserActivity);
    handleUserActivity();
    return () => {
      window.removeEventListener('mousemove', handleUserActivity);
      window.removeEventListener('touchstart', handleUserActivity);
      window.removeEventListener('click', handleUserActivity);
      window.removeEventListener('keydown', handleUserActivity);
      if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [handleUserActivity]);

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-black text-white relative">
      <div className="absolute inset-0 z-0">
        <VisualizerCanvas 
          params={params} 
          getAudioMetrics={getAudioMetrics}
