import { useEffect, useRef, useState, useCallback } from 'react';

export const useAudioAnalyzer = () => {
  const [isActive, setIsActive] = useState(false);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const dataArrayRef = useRef<Uint8Array | null>(null);

  const startAudio = async () => {
    try {
      if (!audioContextRef.current) {
        audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      }

      // Resume context if suspended (browser policy)
      if (audioContextRef.current.state === 'suspended') {
        await audioContextRef.current.resume();
      }

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      analyserRef.current = audioContextRef.current.createAnalyser();
      analyserRef.current.fftSize = 2048; // Standard resolution
      analyserRef.current.smoothingTimeConstant = 0.85;

      sourceRef.current = audioContextRef.current.createMediaStreamSource(stream);
      sourceRef.current.connect(analyserRef.current);

      dataArrayRef.current = new Uint8Array(analyserRef.current.frequencyBinCount);

      setIsActive(true);
    } catch (err) {
      console.error("Error accessing microphone:", err);
      setIsActive(false);
    }
  };

  const stopAudio = () => {
    if (sourceRef.current) {
      sourceRef.current.disconnect();
    }
    setIsActive(false);
  };

  const getAudioMetrics = useCallback((sensitivity: number, freqRange: number): { volume: number, frequency: number } => {
    if (!analyserRef.current || !dataArrayRef.current || !isActive) {
      return { volume: 0, frequency: 0 };
    }

    analyserRef.current.getByteFrequencyData(dataArrayRef.current);

    // Limit range to relevant frequencies (mostly bass/mids for visuals)
    const rangeLimit = Math.floor(dataArrayRef.current.length * freqRange);

    let totalMagnitude = 0;
    let weightedFrequencySum = 0;

    for (let i = 0; i < rangeLimit; i++) {
      const val = dataArrayRef.current[i];
      // Noise gate
      if (val > 25) { 
        totalMagnitude += val;
        weightedFrequencySum += i * val;
      }
    }

    const average = rangeLimit > 0 ? totalMagnitude / rangeLimit : 0;
    const volume = Math.min((average / 50) * sensitivity, 1.0); 

    let frequency = 0;
    if (totalMagnitude > 0) {
      const centroidBin = weightedFrequencySum / totalMagnitude;
      frequency = centroidBin / rangeLimit;
    }

    return { volume, frequency };
  }, [isActive]);

  return {
    isActive,
    startAudio,
    stopAudio,
    getAudioMetrics
  };
};

import React, { useRef, useEffect } from 'react';
import { VisualizerParams } from '../types';

interface VisualizerCanvasProps {
  params: VisualizerParams;
  getAudioMetrics: (sensitivity: number, freqRange: number) => { volume: number, frequency: number };
}

// Shortest path interpolation for angles
const lerpAngle = (start: number, end: number, amt: number) => {
  const d = end - start;
  const delta = (d + 540) % 360 - 180; 
  return (start + delta * amt + 360) % 360;
};

const VisualizerCanvas: React.FC<VisualizerCanvasProps> = ({ params, getAudioMetrics }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // REFS FOR PERSISTENT LOOP STATE
  // We use refs so we can access the latest values inside the requestAnimationFrame loop
  // without having to restart the loop (which causes stutter/breaks).
  const paramsRef = useRef(params);
  const getMetricsRef = useRef(getAudioMetrics);
  const timeRef = useRef<number>(0);
  const currentHueRef = useRef<number>(params.baseHue);

  // Sync refs with props
  useEffect(() => {
    paramsRef.current = params;
  }, [params]);

  useEffect(() => {
    getMetricsRef.current = getAudioMetrics;
  }, [getAudioMetrics]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    // Resize Observer to handle window changes
    const resizeObserver = new ResizeObserver(entries => {
      const { width, height } = entries[0].contentRect;
      const dpr = window.devicePixelRatio || 1;

      canvas.width = width * dpr;
      canvas.height = height * dpr;

      const ctx = canvas.getContext('2d');
      if(ctx) ctx.scale(dpr, dpr);

      // Keep CSS size matched
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;

      // We store logical size for the draw function to use
      (canvas as any).logicalWidth = width;
      (canvas as any).logicalHeight = height;
    });

    if (canvas.parentElement) {
      resizeObserver.observe(canvas.parentElement);
    }

    let animationFrameId: number;

    const render = () => {
      const ctx = canvas.getContext('2d', { alpha: false });
      if (!ctx) {
         animationFrameId = requestAnimationFrame(render);
         return;
      }

      // Read latest state from REFS
      const p = paramsRef.current;
      const getMetrics = getMetricsRef.current;

      const { volume, frequency } = getMetrics(p.sensitivity, p.freqRange);

      const width = (canvas as any).logicalWidth || canvas.width;
      const height = (canvas as any).logicalHeight || canvas.height;
      const cx = width / 2;
      const cy = height / 2;

      // Clear with Trail
      ctx.fillStyle = `rgba(0, 0, 0, ${p.trail})`;
      ctx.fillRect(0, 0, width, height);

      // --- DYNAMIC CALCULATIONS ---

      // 1. Center Breathing (Expansion)
      // Volume slightly affects Expansion (K). K=1 is stable circle.
      // We oscillate very slightly around 1.0 based on volume.
      const kPulse = (p.k - 1) + (volume * 0.03); 
      const dynamicK = 1.0 + kPulse;

      // 2. Angular Velocity
      const dynamicPsi = p.psi + (frequency * 0.05);

      // 3. Zoom/Scale
      const minDim = Math.min(width, height);
      const responsiveZoom = p.zoom * minDim;

      // Prepare Math
      const rotReal = Math.cos(dynamicPsi);
      const rotImag = Math.sin(dynamicPsi);

      // Start Point (Centered)
      // We start slightly off-center based on volume to create the "blooming" effect from center
      let zReal = 1.0 + (volume * 0.2); 
      let zImag = 0.0;

      ctx.beginPath();

      let prevX = cx + zReal * responsiveZoom;
      let prevY = cy - zImag * responsiveZoom;
      ctx.moveTo(prevX, prevY);

      // Color Calculation
      let displayBaseHue;
      if (p.harmonicColor) {
        const logFreq = Math.log2(1 + frequency * 32) / 5; 
        const hueOffset = logFreq * 360 * (p.harmonicSensitivity || 1);
        const targetHue = (p.baseHue + hueOffset) % 360;
        // Smooth color transition
        currentHueRef.current = lerpAngle(currentHueRef.current, targetHue, 0.05);
        displayBaseHue = currentHueRef.current;
      } else {
        timeRef.current += p.hueSpeed;
        currentHueRef.current = (p.baseHue + timeRef.current) % 360;
        displayBaseHue = currentHueRef.current;
      }

      // FRACTAL LOOP
      for (let n = 0; n < p.iter; n++) {
        // Zn+1 = Zn * (K * e^iψ) + Z0

        // Scale
        const zrK = zReal * dynamicK;
        const ziK = zImag * dynamicK;

        // Rotate
        let nextReal = (zrK * rotReal - ziK * rotImag);
        let nextImag = (zrK * rotImag + ziK * rotReal);

        // Translate (Z0)
        // Note: p.z0_r should ideally be 0 for perfect centering, 
        // but user might want to offset it.
        nextReal += p.z0_r;
        nextImag += p.z0_i;

        zReal = nextReal;
        zImag = nextImag;

        const px = cx + zReal * responsiveZoom;
        const py = cy - zImag * responsiveZoom;

        ctx.lineTo(px, py);
        prevX = px;
        prevY = py;
      }

      // Stroke Application
      const gradient = ctx.createLinearGradient(0, 0, width, height);
      const intensity = Math.min(volume * 60, 40);
      const secHue = (displayBaseHue + p.hueRange) % 360;

      const col1 = `hsl(${displayBaseHue}, ${p.saturation}%, ${Math.min(100, p.brightness + intensity)}%)`;
      const col2 = `hsl(${secHue}, ${p.saturation}%, ${Math.max(0, p.brightness - 20 + intensity)}%)`;

      gradient.addColorStop(0, col1);
      gradient.addColorStop(1, col2);

      ctx.strokeStyle = gradient;
      ctx.lineWidth = 1 + (volume * 2);
      ctx.lineJoin = 'round';

      if (p.brightness > 30) {
         ctx.shadowBlur = volume * 15;
         ctx.shadowColor = col1;
      }

      ctx.stroke();
      ctx.shadowBlur = 0;

      animationFrameId = requestAnimationFrame(render);
    };

    // Start loop
    render();

    return () => {
      cancelAnimationFrame(animationFrameId);
      resizeObserver.disconnect();
    };
  }, []); // Empty dependency array ensures loop never resets!

  return (
    <div className="w-full h-full relative bg-black overflow-hidden shadow-inner">
      <canvas ref={canvasRef} className="block w-full h-full" />
    </div>
  );
};

export default VisualizerCanvas;

import React, { useState, useEffect, useRef, useCallback } from 'react';
import ControlPanel from './components/ControlPanel';
import VisualizerCanvas from './components/VisualizerCanvas';
import { VisualizerParams, DEFAULT_PARAMS } from './types';
import { useAudioAnalyzer } from './hooks/useAudioAnalyzer';

// --- HARMONIC GEOMETRY ---
// Sacred angles that create perfect symmetries (Kaleidoscope effect)
const HARMONIC_ANGLES = [
  2.39996,            // Golden Angle (Nature's efficiency)
  1.5708,             // 90 deg (Square)
  1.0472,             // 60 deg (Hexagon)
  0.7854,             // 45 deg (Octagon)
  2.0944,             // 120 deg (Triangle)
  0.5236,             // 30 deg (Dodecagon)
  3.14159,            // 180 deg (Line)
  0.15                // Logarithmic Spiral default
];

// Linear interpolation
const lerp = (start: number, end: number, amt: number) => (1 - amt) * start + amt * end;

// Angle interpolation (shortest path)
const lerpAngle = (start: number, end: number, amt: number) => {
  const d = end - start;
  const delta = (d + Math.PI * 2 + Math.PI) % (Math.PI * 2) - Math.PI;
  return start + delta * amt;
};

const App: React.FC = () => {
  const [params, setParams] = useState<VisualizerParams>(DEFAULT_PARAMS);
  const { isActive, startAudio, stopAudio, getAudioMetrics } = useAudioAnalyzer();
  const [controlsVisible, setControlsVisible] = useState(true);

  // Logic Refs
  const hideTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const animationFrameRef = useRef<number>(0);

  // --- PILOT STATE ---
  const pilotRef = useRef({
    targetK: 1.0,
    targetPsi: 2.399,
    targetZ0_r: 0.0,
    targetZ0_i: 0.0,
    targetZoom: 0.35,
    lastBeatTime: 0,
    currentParams: { ...DEFAULT_PARAMS }
  });

  const toggleAudio = () => {
    if (isActive) {
      stopAudio();
    } else {
      startAudio();
    }
  };

  const handleUserActivity = useCallback(() => {
    setControlsVisible(true);
    if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
    hideTimeoutRef.current = setTimeout(() => {
      setControlsVisible(false);
    }, 4000);
  }, []);

  // --- AUTO PILOT ENGINE ---
  useEffect(() => {
    if (!params.autoPilot) {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      return;
    }

    const updateLoop = () => {
      const { volume, frequency } = getAudioMetrics(params.sensitivity, params.freqRange);
      const now = Date.now();
      const p = pilotRef.current;

      // --- LOGIC: RANDOM HARMONIC SHIFTS BASED ON SOUND ---

      // 1. BEAT DETECTION
      // If volume spikes significantly and enough time has passed, trigger a shift
      // Threshold: 0.35 volume (normalized). Cooldown: 2 seconds.
      const isBeat = volume > 0.35;
      const canShift = (now - p.lastBeatTime) > 3000;

      if (isBeat && canShift) {
        // TRIGGER: New Random Configuration
        p.lastBeatTime = now;

        // Pick a random harmonic angle
        const randomIdx = Math.floor(Math.random() * HARMONIC_ANGLES.length);
        p.targetPsi = HARMONIC_ANGLES[randomIdx];

        // Occasionally flip the zoom for variety (Zoom in or out)
        p.targetZoom = Math.random() > 0.5 ? 0.25 : 0.45;

        // Keep Z0 centered (0,0) but maybe add microscopic drift
        p.targetZ0_r = 0; 
        p.targetZ0_i = 0;
      }

      // 2. CONTINUOUS MODULATION

      // Expansion (K):
      // Volume pushes K slightly to "Breathe". 
      // Base is 1.0 (Stable). Max deviation 0.02.
      // We want to keep it centered and full screen, so K must be close to 1.
      p.targetK = 1.0 + (volume * 0.015);

      // Rotation (Psi) Drift:
      // Add a tiny constant rotation based on frequency to keep it alive even without beats
      p.targetPsi += (frequency * 0.0005);

      // 3. FLUID PHYSICS (INTERPOLATION)
      // High viscosity = slow movement.
      const viscosity = params.autoViscosity ?? 0.95;
      const alpha = (1 - viscosity) * 0.1;

      p.currentParams.k = lerp(p.currentParams.k, p.targetK, alpha);
      p.currentParams.psi = lerpAngle(p.currentParams.psi, p.targetPsi, alpha);
      p.currentParams.z0_r = lerp(p.currentParams.z0_r, p.targetZ0_r, alpha);
      p.currentParams.z0_i = lerp(p.currentParams.z0_i, p.targetZ0_i, alpha);
      p.currentParams.zoom = lerp(p.currentParams.zoom, p.targetZoom, alpha * 0.5); // Zoom is slower

      // 4. UPDATE REACT STATE
      setParams(prev => ({
        ...prev,
        k: p.currentParams.k,
        psi: p.currentParams.psi,
        z0_r: p.currentParams.z0_r,
        z0_i: p.currentParams.z0_i,
        zoom: p.currentParams.zoom,
        // Color follows time or harmonics
        baseHue: params.harmonicColor ? prev.baseHue : (prev.baseHue + 0.1) % 360
      }));

      animationFrameRef.current = requestAnimationFrame(updateLoop);
    };

    // Initialize with current state
    pilotRef.current.currentParams = { ...params };
    updateLoop();

    return () => {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [params.autoPilot, params.autoSpeed, params.autoViscosity, isActive]); 

  // Event Listeners
  useEffect(() => {
    window.addEventListener('mousemove', handleUserActivity);
    window.addEventListener('touchstart', handleUserActivity);
    window.addEventListener('click', handleUserActivity);
    window.addEventListener('keydown', handleUserActivity);
    handleUserActivity();
    return () => {
      window.removeEventListener('mousemove', handleUserActivity);
      window.removeEventListener('touchstart', handleUserActivity);
      window.removeEventListener('click', handleUserActivity);
      window.removeEventListener('keydown', handleUserActivity);
      if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [handleUserActivity]);

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-black text-white relative">
      <div className="absolute inset-0 z-0">
        <VisualizerCanvas 
          params={params} 
          getAudioMetrics={getAudioMetrics}
        />
      </div>

      <div className="absolute top-6 right-6 flex gap-4 pointer-events-none z-20 transition-opacity duration-500" style={{ opacity: controlsVisible ? 1 : 0.5 }}>
           <div className={`flex items-center gap-2 px-3 py-1 rounded-full border text-xs font-mono backdrop-blur-sm transition-colors duration-300
             ${isActive 
               ? 'bg-red-500/10 border-red-500/40 text-red-400 animate-pulse' 
               : 'bg-gray-800/30 border-gray-700 text-gray-500'}
           `}>
             <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-red-500' : 'bg-gray-500'}`}></div>
             {isActive ? 'MIC LIVE' : 'MIC OFF'}
           </div>

           {params.autoPilot && (
             <div className="flex items-center gap-2 px-3 py-1 rounded-full border border-indigo-500/40 bg-indigo-500/10 text-indigo-400 text-xs font-mono backdrop-blur-sm shadow-[0_0_15px_rgba(99,102,241,0.3)]">
                <span className="animate-spin mr-1">❖</span> AUTO-HARMONIC
             </div>
           )}
      </div>

      <div 
        className={`
          absolute top-0 left-0 h-full z-30
          transform transition-transform duration-500 ease-in-out
          ${controlsVisible ? 'translate-x-0' : '-translate-x-full'}
        `}
        onMouseEnter={() => {
           if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
           setControlsVisible(true);
        }}
        onMouseLeave={handleUserActivity}
      >
        <ControlPanel 
          params={params} 
          setParams={setParams} 
          audioActive={isActive}
          toggleAudio={toggleAudio}
        />
      </div>
    </div>
  );
};

