const ControlPanel: React.FC<ControlPanelProps> = ({ params, setParams, audioActive, toggleAudio }) => {
  const [isFullscreen, setIsFullscreen] = useState(false);

  useEffect(() => {
    const handleFullScreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };

    document.addEventListener('fullscreenchange', handleFullScreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullScreenChange);
  }, []);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.error(`Error attempting to enable full-screen mode: ${err.message} (${err.name})`);
      });
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  };

  const handleChange = (key: keyof VisualizerParams, value: number | boolean) => {
    // Allow any number, check for NaN to prevent crashes if field is empty temporarily
    if (typeof value === 'number' && isNaN(value)) return;
    setParams(prev => ({ ...prev, [key]: value }));
  };

  const centerSpiral = () => {
    setParams(prev => ({ ...prev, z0_r: 0, z0_i: 0 }));
  };

  const renderControl = (
    label: string, 
    key: keyof VisualizerParams, 
    min: number, 
    max: number, 
    step: number,
    icon?: React.ReactNode,
    disabled: boolean = false
