import React, { useState, useEffect, useRef, useCallback } from 'react';
import ControlPanel from './components/ControlPanel';
import VisualizerCanvas from './components/VisualizerCanvas';
import { VisualizerParams, DEFAULT_PARAMS } from './types';
import { useAudioAnalyzer } from './hooks/useAudioAnalyzer';

// --- HARMONIC GEOMETRY ---
// Sacred angles that create perfect symmetries (Kaleidoscope effect)
const HARMONIC_ANGLES = [
  2.39996,            // Golden Angle (Nature's efficiency)
  1.5708,             // 90 deg (Square)
  1.0472,             // 60 deg (Hexagon)
  0.7854,             // 45 deg (Octagon)
  2.0944,             // 120 deg (Triangle)
  0.5236,             // 30 deg (Dodecagon)
  3.14159,            // 180 deg (Line)
  0.15                // Logarithmic Spiral default
];

// Linear interpolation
const lerp = (start: number, end: number, amt: number) => (1 - amt) * start + amt * end;

// Angle interpolation (shortest path)
const lerpAngle = (start: number, end: number, amt: number) => {
  const d = end - start;
  const delta = (d + Math.PI * 2 + Math.PI) % (Math.PI * 2) - Math.PI;
  return start + delta * amt;
};

// --- MUSIC THEORY HELPERS ---
const getTargetAngleForInterval = (interval: number): number => {
  // Map semitone intervals to Geometric Angles
  switch (interval % 12) {
    case 6: return Math.PI;          // Tritone -> Line (180deg)
    case 4: return (2 * Math.PI) / 3;// Augmented -> Triangle (120deg)
    case 3: return Math.PI / 2;      // Diminished -> Square (90deg)
    case 2: return Math.PI / 3;      // Whole Tone -> Hexagon (60deg)
    case 7: return 2.39996;          // Perfect 5th -> Golden Angle (Organic)
    case 5: return 2.39996;          // Perfect 4th -> Golden Angle (Organic)
    case 0: return 0.15;             // Unison -> Spiral
    default: return 0.5236;          // Others -> Dodecagon/Complex
  }
};

const getCircleOfFifthsHue = (noteIndex: number, startHue: number): number => {
  // Multiply by 7 (Perfect Fifth) to jump around the circle
  const fifthsPosition = (noteIndex * 7) % 12;
  return (startHue + (fifthsPosition * 30)) % 360; // 30 degrees per slice
};

const App: React.FC = () => {
  const [params, setParams] = useState<VisualizerParams>(DEFAULT_PARAMS);
  const { isActive, startAudio, stopAudio, getAudioMetrics } = useAudioAnalyzer();
  const [controlsVisible, setControlsVisible] = useState(true);

  // Logic Refs
  const hideTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const animationFrameRef = useRef<number>(0);

  // --- PILOT STATE ---
  const pilotRef = useRef({
    targetK: 1.0,
    targetPsi: 2.399,
    targetZ0_r: 0.0,
    targetZ0_i: 0.0,
    targetHue: params.baseHue,
    // Note: Zoom is no longer targeted by auto-pilot to allow manual depth control
    lastBeatTime: 0,
    currentParams: { ...DEFAULT_PARAMS }
  });

  const toggleAudio = () => {
    if (isActive) {
      stopAudio();
    } else {
      startAudio();
    }
  };

  const handleUserActivity = useCallback(() => {
    setControlsVisible(true);
    if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
    hideTimeoutRef.current = setTimeout(() => {
      setControlsVisible(false);
    }, 4000);
  }, []);

  // --- AUTO PILOT ENGINE ---
  useEffect(() => {
    if (!params.autoPilot) {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      return;
    }

    const updateLoop = () => {
      const { volume, frequency } = getAudioMetrics(params.sensitivity, params.freqRange);
      const now = Date.now();
      const p = pilotRef.current;

      // --- LOGIC BRANCHING ---

      if (params.autoPilotMode === 'harmonic') {
        // --- HARMONIC MODE (Set Theory) ---

        // 1. Pitch Detection (Approximation)
        // Map normalized frequency (0-1) to discrete notes across 3 octaves
        const rawNote = Math.floor(frequency * 36); 
        const noteIndex = rawNote % 12;
        const interval = Math.abs(noteIndex - params.rootNote) % 12;

        // 2. Geometry Mapping
        // Target Angle based on Interval
        if (volume > 0.1) { // Only change geometry if there is sound
           p.targetPsi = getTargetAngleForInterval(interval);
        }

        // 3. Stability (K)
        // Consonant intervals (0, 7, 5, 4, 3) are stable (K=1)
        // Dissonant intervals (1, 6, 2) create slight instability/breathing
        const isDissonant = [1, 2, 6, 11].includes(interval);
        const kNoise = isDissonant ? (Math.sin(now * 0.01) * 0.02) : 0;

        let rawTargetK = 1.0 + (volume * 0.005) + kNoise;
        p.targetK = Math.max(0.990, Math.min(1.015, rawTargetK));

        // 4. Color Isomorphism (Circle of Fifths)
        // Only update color on significant volume to avoid flickering noise
        if (volume > 0.2) {
           p.targetHue = getCircleOfFifthsHue(noteIndex, params.baseHue);
        }

        p.targetZ0_r = 0;
        p.targetZ0_i = 0;

      } else {
        // --- DRIFT MODE (Original Random Logic) ---

        // Beat Detection
        const isBeat = volume > 0.40;
        const canShift = (now - p.lastBeatTime) > 2500;

        if (isBeat && canShift) {
          p.lastBeatTime = now;
          const randomIdx = Math.floor(Math.random() * HARMONIC_ANGLES.length);
          p.targetPsi = HARMONIC_ANGLES[randomIdx];
          p.targetZ0_r = 0; 
          p.targetZ0_i = 0;
        }

        // Continuous Modulation
        const kDeviation = volume * 0.008; 
        let rawTargetK = 1.0 + kDeviation;
        p.targetK = Math.max(0.995, Math.min(1.008, rawTargetK));
        p.targetPsi += (frequency * 0.0002);

        // Drift mode cycles hue slowly by default in the lerp step below
        p.targetHue = (p.currentParams.baseHue + 0.1) % 360;
      }

      // --- SHARED PHYSICS (Interpolation) ---

      const viscosity = params.autoViscosity ?? 0.96;
      let alpha = (1 - viscosity) * 0.05;

      // Dynamic responsiveness
      if (volume > 0.3) alpha *= 1.2;

      // Apply Interpolation
      p.currentParams.k = lerp(p.currentParams.k, p.targetK, alpha);
      p.currentParams.psi = lerpAngle(p.currentParams.psi, p.targetPsi, alpha);
      p.currentParams.z0_r = lerp(p.currentParams.z0_r, p.targetZ0_r, alpha);
      p.currentParams.z0_i = lerp(p.currentParams.z0_i, p.targetZ0_i, alpha);

      // Color Interpolation
      if (params.autoPilotMode === 'harmonic') {
         p.currentParams.baseHue = lerpAngle(p.currentParams.baseHue, p.targetHue, alpha * 0.5);
      } else {
         p.currentParams.baseHue = p.targetHue; // Drift handles increment manually
      }

      // UPDATE STATE
      setParams(prev => ({
        ...prev,
        k: p.currentParams.k,
        psi: p.currentParams.psi,
        z0_r: p.currentParams.z0_r,
        z0_i: p.currentParams.z0_i,
        baseHue: p.currentParams.baseHue
      }));

      animationFrameRef.current = requestAnimationFrame(updateLoop);
    };

    // Initialize logic state
    pilotRef.current.currentParams = { ...params };
    updateLoop();

    return () => {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [params.autoPilot, params.autoPilotMode, params.autoSpeed, params.autoViscosity, params.rootNote, isActive]); 

  // Event Listeners
  useEffect(() => {
    window.addEventListener('mousemove', handleUserActivity);
    window.addEventListener('touchstart', handleUserActivity);
    window.addEventListener('click', handleUserActivity);
    window.addEventListener('keydown', handleUserActivity);
    handleUserActivity();
    return () => {
      window.removeEventListener('mousemove', handleUserActivity);
      window.removeEventListener('touchstart', handleUserActivity);
      window.removeEventListener('click', handleUserActivity);
      window.removeEventListener('keydown', handleUserActivity);
      if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [handleUserActivity]);

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-black text-white relative">
      <div className="absolute inset-0 z-0">
        <VisualizerCanvas 
          params={params} 
          getAudioMetrics={getAudioMetrics}
        />
      </div>

      <div className="absolute top-6 right-6 flex gap-4 pointer-events-none z-20 transition-opacity duration-500" style={{ opacity: controlsVisible ? 1 : 0.5 }}>
           <div className={`flex items-center gap-2 px-3 py-1 rounded-full border text-xs font-mono backdrop-blur-sm transition-colors duration-300
             ${isActive 
               ? 'bg-red-500/10 border-red-500/40 text-red-400 animate-pulse' 
               : 'bg-gray-800/30 border-gray-700 text-gray-500'}
           `}>
             <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-red-500' : 'bg-gray-500'}`}></div>
             {isActive ? 'MIC LIVE' : 'MIC OFF'}
           </div>

           {params.autoPilot && (
             <div className="flex items-center gap-2 px-3 py-1 rounded-full border border-indigo-500/40 bg-indigo-500/10 text-indigo-400 text-xs font-mono backdrop-blur-sm shadow-[0_0_15px_rgba(99,102,241,0.3)]">
                <span className="animate-spin mr-1">❖</span> 
                {params.autoPilotMode === 'harmonic' ? 'ARQUITECTURA ARMÓNICA' : 'AUTO-DERIVA'}
             </div>
           )}
      </div>

      <div 
        className={`
          absolute top-0 left-0 h-full z-30
          transform transition-transform duration-500 ease-in-out
          ${controlsVisible ? 'translate-x-0' : '-translate-x-full'}
        `}
        onMouseEnter={() => {
           if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
           setControlsVisible(true);
        }}
        onMouseLeave={handleUserActivity}
      >
        <ControlPanel 
          params={params} 
          setParams={setParams} 
          audioActive={isActive}
          toggleAudio={toggleAudio}
        />
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { VisualizerParams } from '../types';
import { Activity, Zap, Maximize, Minimize, RotateCw, Palette, Target, Music, BrainCircuit, Wind, Droplets, Waves, Shuffle } from 'lucide-react';

interface ControlPanelProps {
  params: VisualizerParams;
  setParams: React.Dispatch<React.SetStateAction<VisualizerParams>>;
  audioActive: boolean;
  toggleAudio: () => void;
}

const ControlPanel: React.FC<ControlPanelProps> = ({ params, setParams, audioActive, toggleAudio }) => {
  const [isFullscreen, setIsFullscreen] = useState(false);

  useEffect(() => {
    const handleFullScreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };

    document.addEventListener('fullscreenchange', handleFullScreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullScreenChange);
  }, []);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.error(`Error attempting to enable full-screen mode: ${err.message} (${err.name})`);
      });
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  };

  const handleChange = (key: keyof VisualizerParams, value: number | boolean | string) => {
    // Allow any number, check for NaN to prevent crashes if field is empty temporarily
    if (typeof value === 'number' && isNaN(value)) return;
    setParams(prev => ({ ...prev, [key]: value }));
  };

  const centerSpiral = () => {
    setParams(prev => ({ ...prev, z0_r: 0, z0_i: 0 }));
  };

  const renderControl = (
    label: string, 
    key: keyof VisualizerParams, 
    min: number, 
    max: number, 
    step: number,
    icon?: React.ReactNode,
    disabled: boolean = false
  ) => (
    <div className={`mb-5 transition-opacity duration-500 ${disabled ? 'opacity-40 pointer-events-none' : 'opacity-100'}`}>
      <div className="flex justify-between items-end mb-2">
        <label className="text-xs uppercase tracking-wider text-gray-400 flex items-center gap-2">
          {icon && <span className="text-cyan-400">{icon}</span>}
          {label}
        </label>
        <input
          type="number"
          step="any"
          value={typeof params[key] === 'number' ? Number(params[key]).toFixed(3) : params[key] as number}
          onChange={(e) => handleChange(key, parseFloat(e.target.value))}
          disabled={disabled}
          className="font-mono text-xs text-cyan-300 bg-transparent border-b border-gray-700 focus:border-cyan-500 outline-none text-right w-20 hover:border-gray-500 transition-colors"
        />
      </div>
      <input
        type="range"
        min={min}
        max={max}
        step={step}
        value={params[key] as number}
        onChange={(e) => handleChange(key, parseFloat(e.target.value))}
        disabled={disabled}
        className="w-full h-1 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-cyan-500 hover:accent-cyan-400 focus:outline-none focus:ring-2 focus:ring-cyan-500/30"
      />
    </div>
  );

  return (
    <div className="w-80 bg-gray-900/80 backdrop-blur-xl border-r border-gray-800 h-full flex flex-col shadow-2xl z-10 relative">
      <div className="p-6 border-b border-gray-800">
        <h1 className="text-xl font-bold bg-gradient-to-r from-cyan-400 to-blue-500 bg-clip-text text-transparent flex items-center gap-2">
          <Activity className="w-6 h-6 text-cyan-400" />
          AudioMorphic
        </h1>
        <p className="text-xs text-gray-500 mt-1">Recurrencia Compleja Sonora</p>
      </div>

      <div className="p-6 overflow-y-auto flex-1 custom-scrollbar">
        <div className="mb-8 space-y-3">
          <button
            onClick={toggleAudio}
            className={`w-full py-3 px-4 rounded-lg font-bold transition-all duration-300 flex items-center justify-center gap-2 ${
              audioActive 
                ? 'bg-red-500/10 text-red-400 border border-red-500/50 hover:bg-red-500/20' 
                : 'bg-cyan-500/10 text-cyan-400 border border-cyan-500/50 hover:bg-cyan-500/20 shadow-[0_0_15px_rgba(6,182,212,0.3)]'
            }`}
          >
            {audioActive ? (
              <>Detener Micrófono</>
            ) : (
              <>Iniciar Micrófono</>
            )}
          </button>

          <button
            onClick={toggleFullScreen}
            className={`w-full py-3 px-4 rounded-lg font-bold transition-all duration-300 flex items-center justify-center gap-2 
              ${isFullscreen 
                ? 'bg-purple-500/10 text-purple-400 border border-purple-500/50 hover:bg-purple-500/20' 
                : 'bg-gray-800/50 text-gray-300 border border-gray-600 hover:bg-gray-700 hover:text-white'
