                case 'metatron':
                    // 13 Centers, All connected (78 lines)
                    updateSystem(13, 78, "Cubo de Metatrón", "Energía Masculina. Contenedor de Sólidos Platónicos.");
                    break;
            }
        }

        function setMusicShape(notes, edges, name) {
            currentState.mode = 'music';
            currentState.notes = notes;
            currentState.type = name;

            const V = notes.length;
            const E = (V === 2) ? 1 : edges; // Diameter case

            updateSystem(V, E, name, "Geometría Tonal derivada del Círculo Cromático.");
        }

        function updateSystem(V, E, name, desc) {
            currentState.V = V;
            currentState.E = E;

            // UI Updates
            document.getElementById('activeName').textContent = name;
            document.getElementById('activeDesc').textContent = desc;
            document.getElementById('valV').textContent = V;
            document.getElementById('valE').textContent = E;

            // --- MATHEMATICAL ENGINE (The Unifier) ---
            // 1. Inputs
            // Avoid div by zero or sqrt negative
            const alpha = Math.max(0.1, V / 2); 
            const beta = Math.sqrt(Math.max(0, E));

            // 2. Regime Check
            const isPrimary = alpha >= beta;
            const glow = document.getElementById('regimeGlow');

            if (currentState.type === 'void') {
                glow.className = "absolute inset-0 opacity-10 bg-slate-500"; // Neutral
            } else if (isPrimary) {
                glow.className = "absolute inset-0 opacity-20 bg-emerald-600 transition-colors duration-1000";
            } else {
                glow.className = "absolute inset-0 opacity-20 bg-rose-600 transition-colors duration-1000";
            }

            // 3. Harmonic Triangle Construction
            const c = Math.max(alpha, beta); // Hypotenuse
            const a = Math.min(alpha, beta); // Cathetus A
            const b = Math.sqrt((c*c) - (a*a)); // Base Cathetus

            // 4. Harmonic Factors
            const sigma = c + b; // Expansion
            const gal = c - b;   // Contraction
            const vInvariant = sigma + gal; // Should be 2c

            // Update Math Display
            document.getElementById('valInvariant').textContent = vInvariant.toFixed(2);
            document.getElementById('txtSigma').textContent = sigma.toFixed(2);
            document.getElementById('txtGamma').textContent = gal.toFixed(2);

            // MathJax Formula Update
            const mathEl = document.getElementById('mathOutput');
            mathEl.innerHTML = `
                $$ \\alpha=${alpha.toFixed(2)}, \\beta=${beta.toFixed(2)} \\quad | \\quad
                \\triangle: c=${c.toFixed(2)}, b=${b.toFixed(2)} \\quad | \\quad
                \\Sigma=${sigma.toFixed(2)}, \\Gamma=${gal.toFixed(2)} $$
            `;
            if (window.MathJax) MathJax.typesetPromise();

            // --- RENDERERS ---
            drawMainCanvas(); // The Sacred Geo or Music
            drawTriangle(a, b, c); // The Math
            drawSpiral(sigma, gal, b, c); // The Generated Form
        }

        // --- DRAWING LOGIC: MAIN CANVAS ---

        function drawMainCanvas() {
            const canvas = document.getElementById('mainCanvas');
            const w = canvas.width;
            const h = canvas.height;
            const cx = w/2;
            const cy = h/2;
            ctxMain.clearRect(0,0,w,h);

            // Reset Overlay
            document.getElementById('metaOverlay').style.opacity = '0';

            if (currentState.mode === 'music') {
                drawMusicGeometry(ctxMain, cx, cy);
            } else {
                drawGenesisGeometry(ctxMain, cx, cy);
            }
        }

        function drawGenesisGeometry(ctx, cx, cy) {
            const type = currentState.type;
            const baseRadius = 40; 

            ctx.lineWidth = 1.5;
            ctx.strokeStyle = COLORS.feminine;
            ctx.fillStyle = 'rgba(232, 121, 249, 0.1)'; // faint pink fill

            if (type === 'void') {
                // Particle Noise Effect
                for(let i=0; i<50; i++) {
                    ctx.beginPath();
                    ctx.arc(cx + (Math.random()-0.5)*300, cy + (Math.random()-0.5)*300, Math.random()*2, 0, Math.PI*2);
                    ctx.fillStyle = `rgba(255,255,255,${Math.random()*0.5})`;
                    ctx.fill();
                }
                // Singular Point
                ctx.beginPath();
                ctx.arc(cx, cy, 3, 0, Math.PI*2);
                ctx.fillStyle = '#fff';
                ctx.shadowBlur = 20; ctx.shadowColor = '#fff';
                ctx.fill(); ctx.shadowBlur = 0;
                return;
            }

            // Helper to draw circle
            const circle = (x, y, r, fill=false) => {
                ctx.beginPath();
                ctx.arc(x, y, r, 0, Math.PI*2);
                ctx.stroke();
                if(fill) ctx.fill();
            };

            // 1. Center Sphere (Always present from Seed onwards)
            if (type !== 'vesica') circle(cx, cy, baseRadius, true);

            if (type === 'vesica') {
                // Two circles offset
                const offset = baseRadius / 2;
                circle(cx - offset, cy, baseRadius, true);
                circle(cx + offset, cy, baseRadius, true);
                // Highlight Intersection (Light)
                ctx.save();
                ctx.beginPath();
                ctx.arc(cx - offset, cy, baseRadius, -Math.PI/3, Math.PI/3);
                ctx.arc(cx + offset, cy, baseRadius, Math.PI - Math.PI/3, Math.PI + Math.PI/3);
                ctx.fillStyle = 'rgba(255, 255, 200, 0.5)';
                ctx.shadowBlur = 20; ctx.shadowColor = '#ffff00';
                ctx.fill();
                ctx.restore();
            }

            if (type === 'seed' || type === 'egg' || type === 'flower' || type === 'fruit' || type === 'metatron') {
                // Draw 6 surrounding circles (Seed Layer)
                for (let i=0; i<6; i++) {
                    const angle = i * Math.PI / 3;
                    const x = cx + Math.cos(angle) * baseRadius;
                    const y = cy + Math.sin(angle) * baseRadius;
                    circle(x, y, baseRadius, true);
                }
            }

            if (type === 'flower') {
                // Draw 12 more circles (Layer 2)
                // Positions for Flower of Life grid
                // This is a simplified 19-circle render
                const r = baseRadius;
                // Layer 2 (12 circles)
                // 6 at 2r distance
                for (let i=0; i<6; i++) {
                    const angle = i * Math.PI / 3;
                    circle(cx + Math.cos(angle)*r*2, cy + Math.sin(angle)*r*2, r);
                }
                // 6 in gaps
                for (let i=0; i<6; i++) {
                    const angle = i * Math.PI / 3 + Math.PI/6;
                    const dist = r * Math.sqrt(3);
                    circle(cx + Math.cos(angle)*dist, cy + Math.sin(angle)*dist, r);
                }

                // Zona Pellucida (Outer Rings)
                ctx.beginPath();
                ctx.arc(cx, cy, baseRadius * 3, 0, Math.PI*2);
                ctx.strokeStyle = '#fef08a'; // Yellow barrier
                ctx.lineWidth = 3;
                ctx.stroke();

                // Show Warning Overlay
                document.getElementById('metaOverlay').style.opacity = '1';
            }

            if (type === 'fruit' || type === 'metatron') {
                // Fruit of Life is 13 circles (Star shape)
                // Center + 6 inner + 6 outer at 2r distance inline with inner
                // (Already drew center + 6 inner in 'seed' block above)

                // Draw 6 outer
                for (let i=0; i<6; i++) {
                    const angle = i * Math.PI / 3;
                    const x = cx + Math.cos(angle) * baseRadius * 2;
                    const y = cy + Math.sin(angle) * baseRadius * 2;
                    circle(x, y, baseRadius, true);
                }

                // Gold color for Fruit
                ctx.strokeStyle = '#fbbf24'; 
            }

            if (type === 'metatron') {
                // Draw Lines (Masculine Energy)
                const centers = [];
                centers.push({x:cx, y:cy}); // 0
                // Inner 6
                for(let i=0; i<6; i++){
                    centers.push({
                        x: cx + Math.cos(i*Math.PI/3)*baseRadius,
                        y: cy + Math.sin(i*Math.PI/3)*baseRadius
                    });
                }
                // Outer 6
                for(let i=0; i<6; i++){
                    centers.push({
                        x: cx + Math.cos(i*Math.PI/3)*baseRadius*2,
                        y: cy + Math.sin(i*Math.PI/3)*baseRadius*2
                    });
                }

                ctx.beginPath();
                ctx.strokeStyle = COLORS.masculine;
                ctx.lineWidth = 1;
                // Brute force connect all 13 centers
                for(let i=0; i<centers.length; i++){
                    for(let j=i+1; j<centers.length; j++){
                        ctx.moveTo(centers[i].x, centers[i].y);
                        ctx.lineTo(centers[j].x, centers[j].y);
                    }
                }
                ctx.stroke();
            }
        }

        function drawMusicGeometry(ctx, cx, cy) {
            const r = 120;
            // Draw Circle of Fifths base
            ctx.beginPath();
            ctx.arc(cx, cy, r, 0, Math.PI*2);
            ctx.strokeStyle = '#334155';
            ctx.stroke();

            // Draw Nodes
            const notes = ['Do', 'Sol', 'Re', 'La', 'Mi', 'Si', 'Fa#', 'Do#', 'Sol#', 'Re#', 'La#', 'Fa']; // Circle of Fifths order
            for(let i=0; i<12; i++) {
                const ang = (i*30 - 90) * Math.PI/180;
                const nx = cx + Math.cos(ang)*r;
                const ny = cy + Math.sin(ang)*r;

                // Is Active?
                // Note: The input arrays are chromatic indices. We need to map if we want chromatic viz or fifths viz.
                // For simplicity, let's stick to the Chromatic Circle geometry as requested in previous prompt logic
                // But let's label them chromatically to match the input indices.

                ctx.beginPath();
                ctx.arc(nx, ny, 4, 0, Math.PI*2);
                ctx.fillStyle = currentState.notes.includes(i) ? COLORS.musicNode : '#475569';
                ctx.fill();
            }

            // Draw Polygon
            if (currentState.notes.length > 1) {
                ctx.beginPath();
                ctx.strokeStyle = COLORS.musicLine;
                ctx.lineWidth = 2;
                currentState.notes.forEach((nIndex, i) => {
                    const ang = (nIndex*30 - 90) * Math.PI/180;
                    const x = cx + Math.cos(ang)*r;
                    const y = cy + Math.sin(ang)*r;
                    if (i===0) ctx.moveTo(x, y);
                    else ctx.lineTo(x, y);
                });
                if (currentState.notes.length > 2) ctx.closePath();
                ctx.stroke();
                ctx.fillStyle = 'rgba(99, 102, 241, 0.2)';
                ctx.fill();
            }
        }

        // --- DRAWING LOGIC: MATH CANVASES ---

        function drawTriangle(a, b, c) {
            const w = ctxTri.canvas.width;
            const h = ctxTri.canvas.height;
            ctxTri.clearRect(0,0,w,h);

            // Padding
            const p = 20;
            const scale = Math.min((w-p*2)/(b*1.5 || 1), (h-p*2)/(a*1.2 || 1)) * 0.8;
            if (scale === 0 || !isFinite(scale)) return;

            const ox = p + 40;
            const oy = h - p - 20;

            const pC = {x: ox, y: oy};
            const pA = {x: ox, y: oy - a*scale};
            const pB = {x: ox + b*scale, y: oy};

            // Shape
            ctxTri.beginPath();
            ctxTri.moveTo(pC.x, pC.y);
            ctxTri.lineTo(pA.x, pA.y);
            ctxTri.lineTo(pB.x, pB.y);
            ctxTri.closePath();
            ctxTri.fillStyle = 'rgba(16, 185, 129, 0.1)';
            ctxTri.fill();
            ctxTri.strokeStyle = '#cbd5e1';
            ctxTri.stroke();

            // Highlight Sides
            // A (Vertical)
            ctxTri.beginPath(); ctxTri.moveTo(pC.x, pC.y); ctxTri.lineTo(pA.x, pA.y); 
            ctxTri.strokeStyle = COLORS.triA; ctxTri.lineWidth=3; ctxTri.stroke();
            // B (Base)
            ctxTri.beginPath(); ctxTri.moveTo(pC.x, pC.y); ctxTri.lineTo(pB.x, pB.y); 
            ctxTri.strokeStyle = COLORS.triB; ctxTri.lineWidth=3; ctxTri.stroke();
            // C (Hypot)
            ctxTri.beginPath(); ctxTri.moveTo(pA.x, pA.y); ctxTri.lineTo(pB.x, pB.y); 
            ctxTri.strokeStyle = COLORS.triC; ctxTri.lineWidth=3; ctxTri.stroke();

            // Text
            ctxTri.fillStyle = '#94a3b8'; ctxTri.font = '12px monospace';
            ctxTri.fillText(`a:${a.toFixed(1)}`, pC.x-35, pC.y - a*scale/2);
            ctxTri.fillText(`b:${b.toFixed(1)}`, pC.x + b*scale/2, pC.y + 15);
        }

        function drawSpiral(sigma, gal, b, c) {
            const w = ctxSpiral.canvas.width;
            const h = ctxSpiral.canvas.height;
            const cx = w/2;
            const cy = h/2;
            ctxSpiral.clearRect(0,0,w,h);

            // Logic: k = decay, psi = angle
            let k = (sigma === 0) ? 0 : gal / sigma;
            k = Math.pow(k, 0.2); // Visual dampening so spiral is visible

            // Psi is angle of triangle (cos psi = b/c)
            const psi = (c===0) ? 0 : Math.acos(b/c);

            let r = Math.min(w,h)/2 * 0.9;
            let theta = 0;

            ctxSpiral.beginPath();
            ctxSpiral.moveTo(cx + r, cy);
            ctxSpiral.strokeStyle = '#a5b4fc';
            ctxSpiral.lineWidth = 2;

            for(let i=0; i<300; i++){
                if (r < 2) break;
                const x = cx + r*Math.cos(theta);
                const y = cy + r*Math.sin(theta);
                ctxSpiral.lineTo(x, y);

                theta += psi;
                r *= k;
            }
            ctxSpiral.stroke();
        }

        // Init
        window.onload = () => {
            setGenesisPhase('void');
        };

    </script>
</body>
</html>

