import React, { useState, useEffect } from 'react';
import { VisualizerParams } from '../types';
import { Activity, Zap, Maximize, Minimize, RotateCw, Palette, Target, Music, BrainCircuit, Wind, Droplets, Waves, Shuffle, Sprout } from 'lucide-react';

interface ControlPanelProps {
  params: VisualizerParams;
  setParams: React.Dispatch<React.SetStateAction<VisualizerParams>>;
  audioActive: boolean;
  toggleAudio: () => void;
}

const GENESIS_NAMES = [
  "I. El Vacío",
  "II. Vesica Piscis",
  "III. Semilla de la Vida",
  "IV. Huevo de la Vida",
  "V. Flor de la Vida",
  "VI. Fruto de la Vida",
  "VII. Cubo de Metatrón"
];

const ControlPanel: React.FC<ControlPanelProps> = ({ params, setParams, audioActive, toggleAudio }) => {
  const [isFullscreen, setIsFullscreen] = useState(false);

  useEffect(() => {
    const handleFullScreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };

    document.addEventListener('fullscreenchange', handleFullScreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullScreenChange);
  }, []);

  const toggleFullScreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen().catch(err => {
        console.error(`Error attempting to enable full-screen mode: ${err.message} (${err.name})`);
      });
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  };

  const handleChange = (key: keyof VisualizerParams, value: number | boolean | string) => {
    // Allow any number, check for NaN to prevent crashes if field is empty temporarily
    if (typeof value === 'number' && isNaN(value)) return;
    setParams(prev => ({ ...prev, [key]: value }));
  };

  const centerSpiral = () => {
    setParams(prev => ({ ...prev, z0_r: 0, z0_i: 0 }));
  };

  const renderControl = (
    label: string, 
    key: keyof VisualizerParams, 
    min: number, 
    max: number, 
    step: number,
    icon?: React.ReactNode,
    disabled: boolean = false
  ) => (
    <div className={`mb-5 transition-opacity duration-500 ${disabled ? 'opacity-40 pointer-events-none' : 'opacity-100'}`}>
      <div className="flex justify-between items-end mb-2">
        <label className="text-xs uppercase tracking-wider text-gray-400 flex items-center gap-2">
          {icon && <span className="text-cyan-400">{icon}</span>}
          {label}
        </label>
        <input
          type="number"
          step="any"
          value={typeof params[key] === 'number' ? Number(params[key]).toFixed(3) : params[key] as number}
          onChange={(e) => handleChange(key, parseFloat(e.target.value))}
          disabled={disabled}
          className="font-mono text-xs text-cyan-300 bg-transparent border-b border-gray-700 focus:border-cyan-500 outline-none text-right w-20 hover:border-gray-500 transition-colors"
        />
      </div>
      <input
        type="range"
        min={min}
        max={max}
        step={step}
        value={params[key] as number}
        onChange={(e) => handleChange(key, parseFloat(e.target.value))}
        disabled={disabled}
        className="w-full h-1 bg-gray-700 rounded-lg appearance-none cursor-pointer accent-cyan-500 hover:accent-cyan-400 focus:outline-none focus:ring-2 focus:ring-cyan-500/30"
      />
    </div>
  );

  return (
    <div className="w-80 bg-gray-900/80 backdrop-blur-xl border-r border-gray-800 h-full flex flex-col shadow-2xl z-10 relative">
      <div className="p-6 border-b border-gray-800">
        <h1 className="text-xl font-bold bg-gradient-to-r from-cyan-400 to-blue-500 bg-clip-text text-transparent flex items-center gap-2">
          <Activity className="w-6 h-6 text-cyan-400" />
          AudioMorphic
        </h1>
        <p className="text-xs text-gray-500 mt-1">Recurrencia Compleja Sonora</p>
      </div>

      <div className="p-6 overflow-y-auto flex-1 custom-scrollbar">
        <div className="mb-8 space-y-3">
          <button
            onClick={toggleAudio}
            className={`w-full py-3 px-4 rounded-lg font-bold transition-all duration-300 flex items-center justify-center gap-2 ${
              audioActive 
                ? 'bg-red-500/10 text-red-400 border border-red-500/50 hover:bg-red-500/20' 
                : 'bg-cyan-500/10 text-cyan-400 border border-cyan-500/50 hover:bg-cyan-500/20 shadow-[0_0_15px_rgba(6,182,212,0.3)]'
            }`}
          >
            {audioActive ? (
              <>Detener Micrófono</>
            ) : (
              <>Iniciar Micrófono</>
            )}
          </button>

          <button
            onClick={toggleFullScreen}
            className={`w-full py-3 px-4 rounded-lg font-bold transition-all duration-300 flex items-center justify-center gap-2 
              ${isFullscreen 
                ? 'bg-purple-500/10 text-purple-400 border border-purple-500/50 hover:bg-purple-500/20' 
                : 'bg-gray-800/50 text-gray-300 border border-gray-600 hover:bg-gray-700 hover:text-white'
              }`}
          >
            {isFullscreen ? <Minimize className="w-4 h-4" /> : <Maximize className="w-4 h-4" />}
            {isFullscreen ? 'Salir de Pantalla' : 'Pantalla Completa'}
          </button>
        </div>

        <div className="space-y-6">

          {/* Auto Pilot Section */}
          <div className={`p-4 rounded-lg border transition-all duration-500 ${params.autoPilot ? 'bg-indigo-900/30 border-indigo-500/50 shadow-[0_0_10px_rgba(99,102,241,0.2)]' : 'bg-gray-800/40 border-gray-700/50'}`}>
             <div className="flex justify-between items-center mb-2">
               <h3 className="text-sm font-semibold text-white flex items-center gap-2">
                <BrainCircuit className={`w-4 h-4 ${params.autoPilot ? 'text-indigo-400 animate-pulse' : 'text-gray-500'}`} /> 
                Piloto Automático
              </h3>
              <div 
                 onClick={() => handleChange('autoPilot', !params.autoPilot)}
                 className={`w-10 h-5 rounded-full relative cursor-pointer transition-colors duration-300 ${params.autoPilot ? 'bg-indigo-500 border border-indigo-400' : 'bg-gray-700 border border-gray-600'}`}
               >
                 <div className={`absolute top-0.5 w-3.5 h-3.5 rounded-full bg-white shadow-sm transition-all duration-300 ${params.autoPilot ? 'left-5' : 'left-1'}`}></div>
               </div>
             </div>

             {params.autoPilot && (
                <div className="mt-4 pt-4 border-t border-indigo-500/30 animate-in fade-in slide-in-from-top-2 duration-500">

                    {/* Mode Selector */}
                    <div className="flex bg-gray-900/50 p-1 rounded-lg mb-4 border border-indigo-500/20">
                      <button
                        onClick={() => handleChange('autoPilotMode', 'drift')}
                        className={`flex-1 flex items-center justify-center gap-1 py-1.5 text-[9px] uppercase font-bold rounded transition-all ${
                          params.autoPilotMode === 'drift' 
                            ? 'bg-indigo-500 text-white shadow-sm' 
                            : 'text-gray-400 hover:text-gray-200'
                        }`}
                        title="Modo Aleatorio"
                      >
                        <Shuffle size={10} /> Deriva
                      </button>
                      <button
                        onClick={() => handleChange('autoPilotMode', 'harmonic')}
                        className={`flex-1 flex items-center justify-center gap-1 py-1.5 text-[9px] uppercase font-bold rounded transition-all ${
                          params.autoPilotMode === 'harmonic' 
                            ? 'bg-indigo-500 text-white shadow-sm' 
                            : 'text-gray-400 hover:text-gray-200'
                        }`}
                        title="Teoría Musical"
                      >
                        <Waves size={10} /> Armónico
                      </button>
                      <button
                        onClick={() => handleChange('autoPilotMode', 'genesis')}
                        className={`flex-1 flex items-center justify-center gap-1 py-1.5 text-[9px] uppercase font-bold rounded transition-all ${
                          params.autoPilotMode === 'genesis' 
                            ? 'bg-emerald-500 text-white shadow-sm' 
                            : 'text-gray-400 hover:text-gray-200'
                        }`}
                        title="Geometría Sagrada"
                      >
                        <Sprout size={10} /> Génesis
                      </button>
                    </div>

                    {/* Genesis Phase Indicator */}
                    {params.autoPilotMode === 'genesis' && (
                       <div className="mb-4 text-center p-2 bg-emerald-900/30 rounded border border-emerald-500/30">
                          <span className="text-[10px] text-emerald-300 uppercase tracking-widest block mb-1">Fase Actual</span>
                          <span className="text-xs font-serif text-white font-bold">{GENESIS_NAMES[params.genesisStage]}</span>
                       </div>
                    )}

                    {renderControl("Viscosidad", "autoViscosity", 0.01, 0.999, 0.001, <Droplets className="w-3 h-3"/>)}
                    {params.autoPilotMode === 'drift' && renderControl("Velocidad Deriva", "autoSpeed", 0.01, 0.5, 0.01, <Wind className="w-3 h-3"/>)}
                </div>
             )}

             <p className="text-[10px] text-gray-400 leading-tight mt-2">
               {params.autoPilot 
                 ? (
                    params.autoPilotMode === 'harmonic' ? 'Modo: Geometría basada en intervalos musicales y armonía.' :
                    params.autoPilotMode === 'genesis' ? 'Modo: Secuencia evolutiva de geometría sagrada.' :
                    'Modo: Transformación aleatoria fluida.'
                   )
                 : 'Ajuste manual completo.'}
             </p>
          </div>

          <div className="bg-gray-800/40 p-4 rounded-lg border border-gray-700/50 hover:bg-gray-800/60 transition-colors">
            <h3 className="text-sm font-semibold text-white mb-4 flex items-center gap-2">
              <Zap className="w-4 h-4 text-yellow-400" /> Reactividad
            </h3>
            {renderControl("Sensibilidad", "sensitivity", 0.1, 5.0, 0.1)}
            {renderControl("Espectro Freq", "freqRange", 0.1, 1.0, 0.05)}
            {renderControl("Persistencia", "trail", 0.01, 0.8, 0.01)}
          </div>

          <div className="bg-gray-800/40 p-4 rounded-lg border border-gray-700/50 hover:bg-gray-800/60 transition-colors">
            <h3 className="text-sm font-semibold text-white mb-4 flex items-center gap-2">
              <Palette className="w-4 h-4 text-pink-400" /> Cromatismo
            </h3>

            {/* Harmonic Mode Toggle */}
            <div className="mb-5 flex justify-between items-center">
               <label className="text-xs uppercase tracking-wider text-gray-400 flex items-center gap-2 cursor-pointer group">
                  <Music className={`w-4 h-4 ${params.harmonicColor ? 'text-pink-400' : 'text-gray-600'} transition-colors`} />
                  <span className="group-hover:text-gray-300 transition-colors">Color Armónico</span>
               </label>
               <div 
                 onClick={() => handleChange('harmonicColor', !params.harmonicColor)}
                 className={`w-10 h-5 rounded-full relative cursor-pointer transition-colors duration-300 ${params.harmonicColor ? 'bg-pink-500/50 border border-pink-400' : 'bg-gray-700 border border-gray-600'}`}
               >
