import React, { useState, useEffect, useRef, useCallback } from 'react';
import ControlPanel from './components/ControlPanel';
import VisualizerCanvas from './components/VisualizerCanvas';
import { VisualizerParams, DEFAULT_PARAMS } from './types';
import { useAudioAnalyzer } from './hooks/useAudioAnalyzer';

// --- HARMONIC GEOMETRY ---
const HARMONIC_ANGLES = [
  2.39996,            // Golden Angle
  1.5708,             // 90 deg
  1.0472,             // 60 deg
  0.7854,             // 45 deg
  2.0944,             // 120 deg
  0.5236,             // 30 deg
  3.14159,            // 180 deg
  0.15                // Spiral
];

// --- GENESIS GEOMETRY DATA ---
const GENESIS_STAGES = [
  { name: 'Void',     V: 1,  E: 0 },
  { name: 'Vesica',   V: 2,  E: 1 },
  { name: 'Seed',     V: 7,  E: 12 },
  { name: 'Egg',      V: 8,  E: 12 },
  { name: 'Flower',   V: 19, E: 36 },
  { name: 'Fruit',    V: 13, E: 24 },
  { name: 'Metatron', V: 13, E: 78 }
];

// Linear interpolation
const lerp = (start: number, end: number, amt: number) => (1 - amt) * start + amt * end;

// Angle interpolation
const lerpAngle = (start: number, end: number, amt: number) => {
  const d = end - start;
  const delta = (d + Math.PI * 2 + Math.PI) % (Math.PI * 2) - Math.PI;
  return start + delta * amt;
};

// --- MUSIC THEORY HELPERS ---
const getTargetAngleForInterval = (interval: number): number => {
  switch (interval % 12) {
    case 6: return Math.PI;          
    case 4: return (2 * Math.PI) / 3;
    case 3: return Math.PI / 2;      
    case 2: return Math.PI / 3;      
    case 7: return 2.39996;          
    case 5: return 2.39996;          
    case 0: return 0.15;             
    default: return 0.5236;          
  }
};

const getCircleOfFifthsHue = (noteIndex: number, startHue: number): number => {
  const fifthsPosition = (noteIndex * 7) % 12;
  return (startHue + (fifthsPosition * 30)) % 360; 
};

const App: React.FC = () => {
  const [params, setParams] = useState<VisualizerParams>(DEFAULT_PARAMS);
  const { isActive, startAudio, stopAudio, getAudioMetrics } = useAudioAnalyzer();
  const [controlsVisible, setControlsVisible] = useState(true);

  // Logic Refs
  const hideTimeoutRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const animationFrameRef = useRef<number>(0);

  // --- PILOT STATE ---
  const pilotRef = useRef({
    targetK: 1.0,
    targetPsi: 2.399,
    targetZ0_r: 0.0,
    targetZ0_i: 0.0,
    targetHue: params.baseHue,
    lastBeatTime: 0,
    currentParams: { ...DEFAULT_PARAMS },
    genesisTargetStage: 0 // Target stage index for Genesis mode
  });

  const toggleAudio = () => {
    if (isActive) {
      stopAudio();
    } else {
      startAudio();
    }
  };

  const handleUserActivity = useCallback(() => {
    setControlsVisible(true);
    if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
    hideTimeoutRef.current = setTimeout(() => {
      setControlsVisible(false);
    }, 4000);
  }, []);

  // --- AUTO PILOT ENGINE ---
  useEffect(() => {
    if (!params.autoPilot) {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
      return;
    }

    const updateLoop = () => {
      const { volume, frequency } = getAudioMetrics(params.sensitivity, params.freqRange);
      const now = Date.now();
      const p = pilotRef.current;

      // --- GENESIS MODE (Sacred Geometry / Evolutionary) ---
      if (params.autoPilotMode === 'genesis') {

        // 1. Determine Stage based on Energy (Volume + Freq)
        // This makes the geometry evolve as the music intensifies
        const energy = volume + (frequency * 0.3);
        let targetStageIdx = 0;

        if (energy < 0.05) targetStageIdx = 0; // Void
        else if (energy < 0.15) targetStageIdx = 1; // Vesica
        else if (energy < 0.30) targetStageIdx = 2; // Seed
        else if (energy < 0.45) targetStageIdx = 3; // Egg
        else if (energy < 0.60) targetStageIdx = 4; // Flower
        else if (energy < 0.75) targetStageIdx = 5; // Fruit
        else targetStageIdx = 6; // Metatron

        // Smoothly transition stage (hysteresis)
        if (targetStageIdx !== p.genesisTargetStage) {
          // Slow evolution, fast regression or vice versa? 
          // Let's just update target, but we store current float stage in params.genesisStage? 
          // Actually, let's keep it discrete for visual clarity, but maybe debounce it.
          p.genesisTargetStage = targetStageIdx;
        }

        const stageData = GENESIS_STAGES[p.genesisTargetStage];

        // 2. MATH ENGINE: Alpha, Beta, Sigma, Gamma
        // V = Vertices, E = Edges
        const alpha = Math.max(0.1, stageData.V / 2);
        const beta = Math.sqrt(Math.max(0, stageData.E));

        const c = Math.max(alpha, beta); // Hypotenuse
        const a = Math.min(alpha, beta); // Cathetus
        // b = sqrt(c^2 - a^2)
        const b = Math.sqrt((c*c) - (a*a));

        const sigma = c + b; // Expansion
        const gal = c - b;   // Contraction

        // 3. Calculate Spiral Parameters from Sacred Math
        // Psi (Angle) = arccos(b/c) if c != 0
        const geomPsi = (c === 0) ? 0.15 : Math.acos(b/c);

        // K (Decay) derived from Sigma/Gamma relation
        // k = (Gamma / Sigma)^0.2
        const rawK = (sigma === 0) ? 1.0 : (gal / sigma);
        const geomK = Math.pow(rawK, 0.2);

        // Apply to Targets
        // We add small audio reactivity to K to make it breathe
        p.targetPsi = geomPsi;
        p.targetK = Math.min(1.05, Math.max(0.9, geomK + (volume * 0.02)));
        p.targetZ0_r = 0;
        p.targetZ0_i = 0;

        // Color: Emerald/Gold for Genesis
        // Low stage = Dark/Void, High stage = Gold/Light
        p.targetHue = 160 + (p.genesisTargetStage * 10); // Emerald to Cyan/Blue

      } 
      // --- HARMONIC MODE (Set Theory) ---
      else if (params.autoPilotMode === 'harmonic') {
        const rawNote = Math.floor(frequency * 36); 
        const noteIndex = rawNote % 12;
        const interval = Math.abs(noteIndex - params.rootNote) % 12;

        if (volume > 0.1) { 
           p.targetPsi = getTargetAngleForInterval(interval);
        }

        const isDissonant = [1, 2, 6, 11].includes(interval);
        const kNoise = isDissonant ? (Math.sin(now * 0.01) * 0.02) : 0;

        let rawTargetK = 1.0 + (volume * 0.005) + kNoise;
        p.targetK = Math.max(0.990, Math.min(1.015, rawTargetK));

        if (volume > 0.2) {
           p.targetHue = getCircleOfFifthsHue(noteIndex, params.baseHue);
        }
        p.targetZ0_r = 0;
        p.targetZ0_i = 0;
        p.genesisTargetStage = 0; // Reset
      } 
      // --- DRIFT MODE (Original) ---
      else {
        const isBeat = volume > 0.40;
        const canShift = (now - p.lastBeatTime) > 2500;

        if (isBeat && canShift) {
          p.lastBeatTime = now;
          const randomIdx = Math.floor(Math.random() * HARMONIC_ANGLES.length);
          p.targetPsi = HARMONIC_ANGLES[randomIdx];
          p.targetZ0_r = 0; 
          p.targetZ0_i = 0;
        }

        const kDeviation = volume * 0.008; 
        let rawTargetK = 1.0 + kDeviation;
        p.targetK = Math.max(0.995, Math.min(1.008, rawTargetK));
        p.targetPsi += (frequency * 0.0002);
        p.targetHue = (p.currentParams.baseHue + 0.1) % 360;
        p.genesisTargetStage = 0; // Reset
      }

      // --- SHARED PHYSICS (Interpolation) ---
      const viscosity = params.autoViscosity ?? 0.96;
      let alpha = (1 - viscosity) * 0.05;

      if (volume > 0.3) alpha *= 1.2;

      p.currentParams.k = lerp(p.currentParams.k, p.targetK, alpha);
      p.currentParams.psi = lerpAngle(p.currentParams.psi, p.targetPsi, alpha);
      p.currentParams.z0_r = lerp(p.currentParams.z0_r, p.targetZ0_r, alpha);
      p.currentParams.z0_i = lerp(p.currentParams.z0_i, p.targetZ0_i, alpha);

      if (params.autoPilotMode === 'harmonic' || params.autoPilotMode === 'genesis') {
         p.currentParams.baseHue = lerpAngle(p.currentParams.baseHue, p.targetHue, alpha * 0.5);
      } else {
         p.currentParams.baseHue = p.targetHue; 
      }

      setParams(prev => ({
        ...prev,
        k: p.currentParams.k,
        psi: p.currentParams.psi,
        z0_r: p.currentParams.z0_r,
        z0_i: p.currentParams.z0_i,
        baseHue: p.currentParams.baseHue,
        genesisStage: p.genesisTargetStage // Update stage for Visualizer
      }));

      animationFrameRef.current = requestAnimationFrame(updateLoop);
    };

    pilotRef.current.currentParams = { ...params };
    updateLoop();

    return () => {
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [params.autoPilot, params.autoPilotMode, params.autoSpeed, params.autoViscosity, params.rootNote, isActive]); 

  // Event Listeners
  useEffect(() => {
    window.addEventListener('mousemove', handleUserActivity);
    window.addEventListener('touchstart', handleUserActivity);
    window.addEventListener('click', handleUserActivity);
    window.addEventListener('keydown', handleUserActivity);
    handleUserActivity();
    return () => {
      window.removeEventListener('mousemove', handleUserActivity);
      window.removeEventListener('touchstart', handleUserActivity);
      window.removeEventListener('click', handleUserActivity);
      window.removeEventListener('keydown', handleUserActivity);
      if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
      if (animationFrameRef.current) cancelAnimationFrame(animationFrameRef.current);
    };
  }, [handleUserActivity]);

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-black text-white relative">
      <div className="absolute inset-0 z-0">
        <VisualizerCanvas 
          params={params} 
          getAudioMetrics={getAudioMetrics}
        />
      </div>

      <div className="absolute top-6 right-6 flex gap-4 pointer-events-none z-20 transition-opacity duration-500" style={{ opacity: controlsVisible ? 1 : 0.5 }}>
           <div className={`flex items-center gap-2 px-3 py-1 rounded-full border text-xs font-mono backdrop-blur-sm transition-colors duration-300
             ${isActive 
               ? 'bg-red-500/10 border-red-500/40 text-red-400 animate-pulse' 
               : 'bg-gray-800/30 border-gray-700 text-gray-500'}
           `}>
             <div className={`w-2 h-2 rounded-full ${isActive ? 'bg-red-500' : 'bg-gray-500'}`}></div>
             {isActive ? 'MIC LIVE' : 'MIC OFF'}
           </div>

           {params.autoPilot && (
             <div className="flex items-center gap-2 px-3 py-1 rounded-full border border-indigo-500/40 bg-indigo-500/10 text-indigo-400 text-xs font-mono backdrop-blur-sm shadow-[0_0_15px_rgba(99,102,241,0.3)]">
                <span className="animate-spin mr-1">❖</span> 
                {params.autoPilotMode === 'harmonic' ? 'ARQUITECTURA ARMÓNICA' : 
                 params.autoPilotMode === 'genesis' ? 'GÉNESIS GEOMÉTRICO' : 'AUTO-DERIVA'}
             </div>
           )}
      </div>

      <div 
        className={`
          absolute top-0 left-0 h-full z-30
          transform transition-transform duration-500 ease-in-out
          ${controlsVisible ? 'translate-x-0' : '-translate-x-full'}
        `}
        onMouseEnter={() => {
           if (hideTimeoutRef.current) clearTimeout(hideTimeoutRef.current);
           setControlsVisible(true);
        }}
        onMouseLeave={handleUserActivity}
      >
        <ControlPanel 
          params={params} 
          setParams={setParams} 
          audioActive={isActive}
          toggleAudio={toggleAudio}
        />
      </div>
    </div>
  );
};

export default App;

import React, { useRef, useEffect } from 'react';
import { VisualizerParams } from '../types';

interface VisualizerCanvasProps {
  params: VisualizerParams;
  getAudioMetrics: (sensitivity: number, freqRange: number) => { volume: number, frequency: number };
}

// Shortest path interpolation for angles
const lerpAngle = (start: number, end: number, amt: number) => {
  const d = end - start;
  const delta = (d + 540) % 360 - 180; 
  return (start + delta * amt + 360) % 360;
};

// --- SACRED GEOMETRY DRAWER ---
const drawSacredOverlay = (ctx: CanvasRenderingContext2D, width: number, height: number, stage: number, zoom: number) => {
    const cx = width / 2;
    const cy = height / 2;

    // Base scale relative to visualizer zoom, but constrained
    const minDim = Math.min(width, height);
    // Inverse zoom somewhat to keep geometry visible when fractal is deep, 
    // but scale it up when fractal is close.
    // The visualizer zoom is usually small (0.01 - 0.5).
    // Let's fix a visible base radius for the geometry.
    const r = minDim * 0.15; 

    ctx.lineWidth = 1;
    ctx.strokeStyle = 'rgba(255, 255, 255, 0.1)'; // Very faint

    const circle = (x: number, y: number, rad: number, stroke = true, fill = false) => {
        ctx.beginPath();
        ctx.arc(x, y, rad, 0, Math.PI*2);
        if (fill) { ctx.fillStyle = 'rgba(16, 185, 129, 0.05)'; ctx.fill(); }
        if (stroke) ctx.stroke();
    };

    // Stage 0: Void (Nothing)
    if (stage === 0) return;

    // Center Sphere (Always present Stage 1+)
    circle(cx, cy, r, true, true);

    if (stage === 1) { // Vesica
        circle(cx - r/2, cy, r);
        circle(cx + r/2, cy, r);
    } 
    else if (stage >= 2) { // Seed, Egg, Flower, Fruit, Metatron
        // 6 Surrounding circles
        for (let i = 0; i < 6; i++) {
            const angle = i * Math.PI / 3;
            circle(cx + Math.cos(angle) * r, cy + Math.sin(angle) * r, r);
        }
    }

    if (stage >= 4) { // Flower
        // Layer 2 (12 circles)
        for (let i = 0; i < 6; i++) {
            const angle = i * Math.PI / 3;
            circle(cx + Math.cos(angle)*r*2, cy + Math.sin(angle)*r*2, r);
        }
        for (let i = 0; i < 6; i++) {
            const angle = i * Math.PI / 3 + Math.PI/6;
            const dist = r * Math.sqrt(3);
            circle(cx + Math.cos(angle)*dist, cy + Math.sin(angle)*dist, r);
        }
        // Zona Pellucida
        ctx.beginPath();
        ctx.arc(cx, cy, r * 3, 0, Math.PI*2);
        ctx.strokeStyle = 'rgba(253, 224, 71, 0.2)'; // Yellow tint
        ctx.stroke();
    }

    if (stage >= 5) { // Fruit / Metatron
        // Outer 6 circles for Star shape
        for (let i = 0; i < 6; i++) {
            const angle = i * Math.PI / 3;
            circle(cx + Math.cos(angle)*r*2, cy + Math.sin(angle)*r*2, r);
        }
    }

    if (stage === 6) { // Metatron Lines
        const centers: {x:number, y:number}[] = [{x:cx, y:cy}];
        // Inner 6
        for(let i=0; i<6; i++){
            centers.push({
                x: cx + Math.cos(i*Math.PI/3)*r,
                y: cy + Math.sin(i*Math.PI/3)*r
            });
        }
        // Outer 6
        for(let i=0; i<6; i++){
            centers.push({
                x: cx + Math.cos(i*Math.PI/3)*r*2,
                y: cy + Math.sin(i*Math.PI/3)*r*2
            });
        }

        ctx.beginPath();
        ctx.strokeStyle = 'rgba(239, 68, 68, 0.15)'; // Red tint for masculine energy
        for(let i=0; i<centers.length; i++){
            for(let j=i+1; j<centers.length; j++){
                // Optimize: only draw connections if distance is specific (sacred lengths)
                // But for full Metatron, brute force is accurate
                const dx = centers[i].x - centers[j].x;
                const dy = centers[i].y - centers[j].y;
                const dist = Math.sqrt(dx*dx + dy*dy);
                // Draw if distance is ~ r, r*sqrt(3), or 2r
                if (dist < r * 2.1) {
                    ctx.moveTo(centers[i].x, centers[i].y);
                    ctx.lineTo(centers[j].x, centers[j].y);
                }
            }
        }
        ctx.stroke();
    }
};


const VisualizerCanvas: React.FC<VisualizerCanvasProps> = ({ params, getAudioMetrics }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  // REFS FOR PERSISTENT LOOP STATE
  const paramsRef = useRef(params);
  const getMetricsRef = useRef(getAudioMetrics);
  const timeRef = useRef<number>(0);
  const currentHueRef = useRef<number>(params.baseHue);

  // Sync refs with props
  useEffect(() => {
    paramsRef.current = params;
  }, [params]);

  useEffect(() => {
    getMetricsRef.current = getAudioMetrics;
  }, [getAudioMetrics]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    // Resize Observer to handle window changes
    const resizeObserver = new ResizeObserver(entries => {
      const { width, height } = entries[0].contentRect;
      const dpr = window.devicePixelRatio || 1;

      canvas.width = width * dpr;
      canvas.height = height * dpr;

      const ctx = canvas.getContext('2d');
      if(ctx) ctx.scale(dpr, dpr);

      // Keep CSS size matched
      canvas.style.width = `${width}px`;
      canvas.style.height = `${height}px`;

      // We store logical size for the draw function to use
      (canvas as any).logicalWidth = width;
      (canvas as any).logicalHeight = height;
    });

    if (canvas.parentElement) {
      resizeObserver.observe(canvas.parentElement);
    }

    let animationFrameId: number;

    const render = () => {
      const ctx = canvas.getContext('2d', { alpha: false });
      if (!ctx) {
         animationFrameId = requestAnimationFrame(render);
         return;
      }

      // Read latest state from REFS
      const p = paramsRef.current;
      const getMetrics = getMetricsRef.current;

      const { volume, frequency } = getMetrics(p.sensitivity, p.freqRange);

      const width = (canvas as any).logicalWidth || canvas.width;
      const height = (canvas as any).logicalHeight || canvas.height;
      const cx = width / 2;
      const cy = height / 2;

      // Clear with Trail
      ctx.fillStyle = `rgba(0, 0, 0, ${p.trail})`;
      ctx.fillRect(0, 0, width, height);

      // --- SACRED GEOMETRY BACKGROUND ---
      // Only draw if in Genesis mode (or if user wants to see it)
      if (p.autoPilotMode === 'genesis') {
        drawSacredOverlay(ctx, width, height, p.genesisStage || 0, p.zoom);
      }

      // --- DYNAMIC CALCULATIONS ---

      // 1. Center Breathing (Expansion)
      const kPulse = (p.k - 1) + (volume * 0.03); 
      const dynamicK = 1.0 + kPulse;

      // 2. Angular Velocity
      const dynamicPsi = p.psi + (frequency * 0.05);

      // 3. Zoom/Scale
      const minDim = Math.min(width, height);
      const responsiveZoom = p.zoom * minDim;

      // Prepare Math
      const rotReal = Math.cos(dynamicPsi);
      const rotImag = Math.sin(dynamicPsi);

      // Start Point (Centered)
      let zReal = 1.0 + (volume * 0.2); 
      let zImag = 0.0;

      ctx.beginPath();

      let prevX = cx + zReal * responsiveZoom;
      let prevY = cy - zImag * responsiveZoom;
      ctx.moveTo(prevX, prevY);

      // Color Calculation
      let displayBaseHue;
      if (p.harmonicColor || p.autoPilotMode === 'genesis') {
        let targetHue = p.baseHue;
        if (p.harmonicColor) {
           const logFreq = Math.log2(1 + frequency * 32) / 5; 
           const hueOffset = logFreq * 360 * (p.harmonicSensitivity || 1);
           targetHue = (p.baseHue + hueOffset) % 360;
        }
        // Smooth color transition
        currentHueRef.current = lerpAngle(currentHueRef.current, targetHue, 0.05);
        displayBaseHue = currentHueRef.current;
      } else {
        timeRef.current += p.hueSpeed;
        currentHueRef.current = (p.baseHue + timeRef.current) % 360;
        displayBaseHue = currentHueRef.current;
      }

      // FRACTAL LOOP
      for (let n = 0; n < p.iter; n++) {
        // Zn+1 = Zn * (K * e^iψ) + Z0

        // Scale
        const zrK = zReal * dynamicK;
        const ziK = zImag * dynamicK;

        // Rotate
        let nextReal = (zrK * rotReal - ziK * rotImag);
        let nextImag = (zrK * rotImag + ziK * rotReal);

        // Translate (Z0)
        nextReal += p.z0_r;
        nextImag += p.z0_i;

        zReal = nextReal;
        zImag = nextImag;

        const px = cx + zReal * responsiveZoom;
        const py = cy - zImag * responsiveZoom;

        ctx.lineTo(px, py);
        prevX = px;
        prevY = py;
      }

      // Stroke Application
      const gradient = ctx.createLinearGradient(0, 0, width, height);
      const intensity = Math.min(volume * 60, 40);
      const secHue = (displayBaseHue + p.hueRange) % 360;

      const col1 = `hsl(${displayBaseHue}, ${p.saturation}%, ${Math.min(100, p.brightness + intensity)}%)`;
      const col2 = `hsl(${secHue}, ${p.saturation}%, ${Math.max(0, p.brightness - 20 + intensity)}%)`;

      gradient.addColorStop(0, col1);
      gradient.addColorStop(1, col2);

      ctx.strokeStyle = gradient;
      ctx.lineWidth = 1 + (volume * 2);
      ctx.lineJoin = 'round';

      if (p.brightness > 30) {
         ctx.shadowBlur = volume * 15;
         ctx.shadowColor = col1;
      }

      ctx.stroke();
      ctx.shadowBlur = 0;

      animationFrameId = requestAnimationFrame(render);
    };

    // Start loop
    render();

    return () => {
      cancelAnimationFrame(animationFrameId);
      resizeObserver.disconnect();
    };
  }, []); 

  return (
    <div className="w-full h-full relative bg-black overflow-hidden shadow-inner">
      <canvas ref={canvasRef} className="block w-full h-full" />
    </div>
  );
};

